import { useState, useCallback, useRef, useEffect, useMemo } from 'react';
import type { ExchangeId } from '@deskmodal/data-layer';

/* -------------------------------------------------------------------------- */
/*  useStaleData                                                               */
/*  Timer-based staleness detection driven by price ticks.                     */
/*  Threshold: 5s for streaming data (ticker), 60s for OHLCV.                 */
/* -------------------------------------------------------------------------- */

const STALE_THRESHOLD_MS = 5_000;
const STALE_CHECK_INTERVAL_MS = 1_000;

/** Stale data alert shape. */
export interface StaleDataAlert {
  readonly exchangeId: ExchangeId;
  readonly symbol: string;
  readonly dataType: string;
  readonly staleSinceMs: number;
  readonly lastReceivedAt: number;
}

/** Key format for tracking individual stale alerts. */
function alertKey(exchangeId: ExchangeId, symbol: string, dataType: string): string {
  return `${exchangeId}:${symbol}:${dataType}`;
}

/**
 * Hook that tracks stale data alerts with timer-based detection.
 *
 * Call `recordTick()` on each incoming price tick to record freshness.
 * The hook checks staleness every STALE_CHECK_INTERVAL_MS and sets
 * alerts for symbols that haven't received a tick in STALE_THRESHOLD_MS.
 */
export function useStaleData(): {
  staleAlerts: ReadonlyMap<string, StaleDataAlert>;
  isSymbolStale: (symbol: string, dataType?: string) => boolean;
  isExchangeStale: (exchangeId: ExchangeId) => boolean;
  staleCount: number;
  recordTick: (exchangeId: ExchangeId, symbol: string) => void;
  getLastUpdateAge: (exchangeId: ExchangeId, symbol: string) => number | null;
} {
  const [alerts, setAlerts] = useState<Map<string, StaleDataAlert>>(new Map());
  const lastTickTimes = useRef<Map<string, { exchangeId: ExchangeId; symbol: string; time: number }>>(new Map());

  /** Called by useLivePrices on each tick to record freshness. */
  const recordTick = useCallback((exchangeId: ExchangeId, symbol: string) => {
    const key = `${exchangeId}:${symbol}`;
    lastTickTimes.current.set(key, { exchangeId, symbol, time: Date.now() });
  }, []);

  /** Get milliseconds since last tick for a symbol. */
  const getLastUpdateAge = useCallback((exchangeId: ExchangeId, symbol: string): number | null => {
    const entry = lastTickTimes.current.get(`${exchangeId}:${symbol}`);
    if (!entry) return null;
    return Date.now() - entry.time;
  }, []);

  // Timer that checks staleness every STALE_CHECK_INTERVAL_MS
  useEffect(() => {
    const intervalId = window.setInterval(() => {
      const now = Date.now();
      const newAlerts = new Map<string, StaleDataAlert>();

      for (const [, entry] of lastTickTimes.current) {
        const age = now - entry.time;
        if (age > STALE_THRESHOLD_MS) {
          const aKey = alertKey(entry.exchangeId, entry.symbol, 'ticker');
          newAlerts.set(aKey, {
            exchangeId: entry.exchangeId,
            symbol: entry.symbol,
            dataType: 'ticker',
            staleSinceMs: age - STALE_THRESHOLD_MS,
            lastReceivedAt: entry.time,
          });
        }
      }

      setAlerts((prev) => {
        // Only update state if the stale set changed
        if (prev.size === newAlerts.size) {
          let same = true;
          for (const key of newAlerts.keys()) {
            if (!prev.has(key)) { same = false; break; }
          }
          if (same) return prev;
        }
        return newAlerts;
      });
    }, STALE_CHECK_INTERVAL_MS);

    return () => window.clearInterval(intervalId);
  }, []);

  /** Check if a specific symbol has any stale data. */
  const isSymbolStale = useCallback(
    (symbol: string, dataType?: string): boolean => {
      for (const alert of alerts.values()) {
        if (alert.symbol === symbol || alert.symbol.replace('/', '') === symbol) {
          if (dataType === undefined || alert.dataType === dataType) return true;
        }
      }
      return false;
    },
    [alerts],
  );

  /** Check if a specific exchange has any stale data. */
  const isExchangeStale = useCallback(
    (exchangeId: ExchangeId): boolean => {
      for (const alert of alerts.values()) {
        if (alert.exchangeId === exchangeId) return true;
      }
      return false;
    },
    [alerts],
  );

  return useMemo(
    () => ({
      staleAlerts: alerts,
      isSymbolStale,
      isExchangeStale,
      staleCount: alerts.size,
      recordTick,
      getLastUpdateAge,
    }),
    [alerts, isSymbolStale, isExchangeStale, recordTick, getLastUpdateAge],
  );
}
