import { useMemo, type CSSProperties } from 'react';

/* -------------------------------------------------------------------------- */
/*  LatencySparkline                                                          */
/*  Inline SVG sparkline showing latency over time (30 data points).          */
/* -------------------------------------------------------------------------- */

export interface LatencySparklineProps {
  /** Latency values in milliseconds, ordered oldest to newest. Max 30 points. */
  readonly values: ReadonlyArray<number>;
  /** Width of the sparkline in pixels. */
  readonly width?: number;
  /** Height of the sparkline in pixels. */
  readonly height?: number;
}

const containerStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  flexShrink: 0,
};

/** Maximum number of data points to render. */
const MAX_POINTS = 30;

/**
 * Determine stroke color based on the latest latency value.
 * <50ms = green (good), 50-200ms = yellow (acceptable), >200ms = red (poor).
 */
function latencyColor(latencyMs: number): string {
  if (latencyMs < 50) return 'var(--ts-status-success, #22c55e)';
  if (latencyMs < 200) return 'var(--ts-status-warning, #eab308)';
  return 'var(--ts-status-error, #ef4444)';
}

export function LatencySparkline({
  values,
  width = 80,
  height = 20,
}: LatencySparklineProps): React.JSX.Element {
  const pathData = useMemo(() => {
    const points = values.slice(-MAX_POINTS);
    if (points.length < 2) return '';

    const maxVal = Math.max(...points, 1);
    const minVal = Math.min(...points, 0);
    const range = maxVal - minVal || 1;
    const padding = 1;
    const drawWidth = width - padding * 2;
    const drawHeight = height - padding * 2;

    const segments: string[] = [];
    for (let i = 0; i < points.length; i++) {
      const x = padding + (i / (points.length - 1)) * drawWidth;
      const y = padding + drawHeight - ((points[i]! - minVal) / range) * drawHeight;
      segments.push(i === 0 ? `M ${x} ${y}` : `L ${x} ${y}`);
    }

    return segments.join(' ');
  }, [values, width, height]);

  const lastValue = values.length > 0 ? values[values.length - 1]! : 0;
  const color = latencyColor(lastValue);

  if (values.length < 2) {
    return (
      <span
        style={{
          ...containerStyle,
          fontSize: 'var(--ts-font-xs)',
          color: 'var(--ts-text-tertiary)',
        }}
      >
        --
      </span>
    );
  }

  return (
    <svg
      width={width}
      height={height}
      viewBox={`0 0 ${width} ${height}`}
      style={containerStyle}
      aria-label={`Latency sparkline: latest ${lastValue}ms`}
      role="img"
    >
      <path
        d={pathData}
        fill="none"
        stroke={color}
        strokeWidth={1.5}
        strokeLinecap="round"
        strokeLinejoin="round"
      />
    </svg>
  );
}

LatencySparkline.displayName = 'LatencySparkline';
