import { useState, useCallback, useRef, useEffect, forwardRef } from 'react';
import { usePress } from '@react-aria/interactions';
import { Badge, Button, Input } from '@deskmodal/ui-components';
import { ChevronDown, Key, Star, StarOff } from 'lucide-react';
import type { ExchangeId } from '@deskmodal/data-layer';
import type { ExchangeDetail } from '../hooks/use-exchange-connections';
import type { ExchangeDQS } from '../hooks/use-dqs';
import type { LivePrice } from '../hooks/use-live-prices';
import type { ExchangeCredentials, CredentialStatus } from '../hooks/use-exchange-credentials';
import { LatencySparkline } from './LatencySparkline';
import { DqsBreakdown } from './DqsBreakdown';
import { priceFeedClient } from '../services/price-feed-client';

/* -------------------------------------------------------------------------- */
/*  ExchangeRow                                                               */
/*  Compact exchange row with expandable inline detail panel.                 */
/* -------------------------------------------------------------------------- */

/** Exchanges that require API credentials to connect (Coinbase public feeds are free). */
const AUTH_REQUIRED_EXCHANGES = new Set<string>([]);

/** Connection transition timeout in milliseconds. */
const CONNECT_TIMEOUT_MS = 10_000;

/** Disconnect confirmation revert timeout in milliseconds. */
const DISCONNECT_CONFIRM_TIMEOUT_MS = 3_000;

export interface ExchangeRowProps {
  /** Exchange detail data. */
  readonly exchange: ExchangeDetail;
  /** DQS score for this exchange (if available). */
  readonly dqs?: ExchangeDQS;
  /** Live prices for this exchange's subscribed symbols. */
  readonly livePrices: ReadonlyArray<LivePrice>;
  /** Rolling latency history (up to 30 values). */
  readonly latencyHistory: ReadonlyArray<number>;
  /** Whether this exchange has credentials configured (boolean flag only). */
  readonly credentialStatus: CredentialStatus;
  /** Whether this row is expanded. */
  readonly expanded: boolean;
  /** Toggle expand state. */
  readonly onToggle: () => void;
  /** Connect to this exchange. */
  readonly onConnect: (exchangeId: ExchangeId) => void;
  /** Disconnect from this exchange. */
  readonly onDisconnect: (exchangeId: ExchangeId) => void;
  /** Save credentials for this exchange. */
  readonly onSaveCredentials: (exchangeId: ExchangeId, credentials: ExchangeCredentials) => void;
  /** Toast callback for error notifications. */
  readonly onError?: (message: string) => void;
  /** Check if a symbol's data is stale (no tick in >5s). */
  readonly isSymbolStale?: (exchangeId: ExchangeId, symbol: string) => boolean;
}

/* ----- Structured logging ------------------------------------------------ */

function structuredLog(level: 'error' | 'warn' | 'info', message: string): void {
  const win = window as { deskmodal?: { log?: (level: string, msg: string) => void } };
  if (win.deskmodal?.log) {
    win.deskmodal.log(level, message);
  }
}

/* ----- Helpers ----------------------------------------------------------- */

function renderStarIcons(rating: number): React.JSX.Element[] {
  const filled = Math.min(5, Math.max(1, rating));
  const stars: React.JSX.Element[] = [];
  for (let i = 0; i < 5; i++) {
    if (i < filled) {
      stars.push(<Star key={i} size={11} fill="currentColor" />);
    } else {
      stars.push(<StarOff key={i} size={11} />);
    }
  }
  return stars;
}

function formatPrice(price: number): string {
  if (price >= 1000) return price.toLocaleString(undefined, { maximumFractionDigits: 0 });
  if (price >= 1) return price.toLocaleString(undefined, { minimumFractionDigits: 2, maximumFractionDigits: 2 });
  if (price >= 0.01) return price.toLocaleString(undefined, { minimumFractionDigits: 4, maximumFractionDigits: 4 });
  return price.toLocaleString(undefined, { minimumFractionDigits: 6, maximumFractionDigits: 6 });
}

function formatChange(pct: number | undefined): string {
  if (pct === undefined) return '';
  const sign = pct >= 0 ? '+' : '';
  return `${sign}${pct.toFixed(2)}%`;
}

function getDirection(change: number | undefined): 'bullish' | 'bearish' | 'neutral' {
  if (change === undefined || change === 0) return 'neutral';
  return change > 0 ? 'bullish' : 'bearish';
}

function formatAge(timestamp: number): string {
  const ageMs = Date.now() - timestamp;
  if (ageMs < 1000) return '<1s';
  if (ageMs < 60_000) return `${Math.floor(ageMs / 1000)}s`;
  if (ageMs < 3_600_000) return `${Math.floor(ageMs / 60_000)}m`;
  return `${Math.floor(ageMs / 3_600_000)}h`;
}

function formatSpread(bid: number, ask: number): string {
  const spread = ask - bid;
  if (bid >= 1000) return spread.toFixed(0);
  if (bid >= 1) return spread.toFixed(2);
  if (bid >= 0.01) return spread.toFixed(4);
  return spread.toFixed(6);
}

/* ----- Credential inline form -------------------------------------------- */

const CredentialForm = forwardRef<HTMLFormElement, {
  exchangeId: ExchangeId;
  onSave: (exchangeId: ExchangeId, credentials: ExchangeCredentials) => void;
  onConnect: (exchangeId: ExchangeId) => void;
  onCancel: () => void;
}>(function CredentialForm({ exchangeId, onSave, onConnect, onCancel }, ref) {
  // Use uncontrolled refs for credential inputs (Decision D5, P1-SEC-3)
  const apiKeyRef = useRef<HTMLInputElement>(null);
  const apiSecretRef = useRef<HTMLInputElement>(null);
  const passphraseRef = useRef<HTMLInputElement>(null);
  const [formState, setFormState] = useState<'idle' | 'saving' | 'saved'>('idle');

  // Auto-focus first input on mount
  useEffect(() => {
    apiKeyRef.current?.focus();
  }, []);

  // Clear refs on unmount
  useEffect(() => {
    return () => {
      if (apiKeyRef.current) apiKeyRef.current.value = '';
      if (apiSecretRef.current) apiSecretRef.current.value = '';
      if (passphraseRef.current) passphraseRef.current.value = '';
    };
  }, []);

  const handleSubmit = useCallback((e: React.FormEvent) => {
    e.preventDefault();
    const apiKey = apiKeyRef.current?.value.trim() ?? '';
    const apiSecret = apiSecretRef.current?.value.trim() ?? '';
    const passphrase = passphraseRef.current?.value.trim() || undefined;

    if (apiKey.length === 0 || apiSecret.length === 0) return;

    setFormState('saving');

    const creds: ExchangeCredentials = { apiKey, apiSecret, passphrase };

    priceFeedClient
      .setCredentials(exchangeId, {
        exchange: exchangeId,
        apiKey: creds.apiKey,
        apiSecret: creds.apiSecret,
        passphrase: creds.passphrase,
      })
      .then((result) => {
        if (result.success) {
          onSave(exchangeId, creds);
          onConnect(exchangeId);
          setFormState('saved');
          // Clear input values after successful submission
          if (apiKeyRef.current) apiKeyRef.current.value = '';
          if (apiSecretRef.current) apiSecretRef.current.value = '';
          if (passphraseRef.current) passphraseRef.current.value = '';
        } else {
          setFormState('idle');
          structuredLog('error', `[ExchangeRow] Credential save failed for ${exchangeId}: ${result.error ?? 'unknown'}`);
        }
      })
      .catch((err) => {
        setFormState('idle');
        structuredLog('error', `[ExchangeRow] Credential save failed for ${exchangeId}: ${String(err)}`);
      });
  }, [exchangeId, onSave, onConnect]);

  const handleKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (e.key === 'Escape') {
      e.preventDefault();
      onCancel();
    }
  }, [onCancel]);

  return (
    <form
      ref={ref}
      data-ts-credential-section=""
      onSubmit={handleSubmit}
      onKeyDown={handleKeyDown}
    >
      <span data-ts-credential-title="">API Credentials</span>

      <div data-ts-credential-field="">
        <label data-ts-credential-label="" htmlFor={`${exchangeId}-api-key`}>
          API Key
        </label>
        <Input
          ref={apiKeyRef}
          id={`${exchangeId}-api-key`}
          aria-label="API Key"
          placeholder="Enter API key..."
          size="sm"
          type="password"
          autoComplete="off"
        />
      </div>

      <div data-ts-credential-field="">
        <label data-ts-credential-label="" htmlFor={`${exchangeId}-api-secret`}>
          API Secret
        </label>
        <Input
          ref={apiSecretRef}
          id={`${exchangeId}-api-secret`}
          aria-label="API Secret"
          placeholder="Enter API secret..."
          size="sm"
          type="password"
          autoComplete="off"
        />
      </div>

      {exchangeId === 'coinbase' && (
        <div data-ts-credential-field="">
          <label data-ts-credential-label="" htmlFor={`${exchangeId}-passphrase`}>
            Passphrase (optional)
          </label>
          <Input
            ref={passphraseRef}
            id={`${exchangeId}-passphrase`}
            aria-label="Passphrase"
            placeholder="Enter passphrase..."
            size="sm"
            type="password"
            autoComplete="off"
          />
        </div>
      )}

      <div data-ts-credential-actions="">
        <Button
          type="submit"
          variant="primary"
          size="sm"
          disabled={formState === 'saving'}
        >
          {formState === 'saving' ? 'Saving...' : formState === 'saved' ? 'Saved' : 'Save & Connect'}
        </Button>
      </div>
    </form>
  );
});

CredentialForm.displayName = 'CredentialForm';

/* ----- Component --------------------------------------------------------- */

export const ExchangeRow = forwardRef<HTMLDivElement, ExchangeRowProps>(function ExchangeRow(
  {
    exchange,
    dqs,
    livePrices,
    latencyHistory,
    credentialStatus,
    expanded,
    onToggle,
    onConnect,
    onDisconnect,
    onSaveCredentials,
    onError,
    isSymbolStale,
  },
  ref,
) {
  const needsAuth = AUTH_REQUIRED_EXCHANGES.has(exchange.id) && credentialStatus === 'none';
  const statusLabel = needsAuth && exchange.status === 'disconnected' ? 'needs API key' : exchange.status;

  // Connection transition state
  const [localStatus, setLocalStatus] = useState<'idle' | 'connecting' | 'disconnecting'>('idle');
  const timeoutRef = useRef<number | null>(null);

  // Disconnect confirmation state
  const [confirmDisconnect, setConfirmDisconnect] = useState(false);
  const confirmTimeoutRef = useRef<number | null>(null);

  // Clean up timeouts on unmount
  useEffect(() => {
    return () => {
      if (timeoutRef.current !== null) window.clearTimeout(timeoutRef.current);
      if (confirmTimeoutRef.current !== null) window.clearTimeout(confirmTimeoutRef.current);
    };
  }, []);

  // Reset local status when service status catches up
  useEffect(() => {
    if (exchange.status === 'connected' && localStatus === 'connecting') {
      setLocalStatus('idle');
      if (timeoutRef.current !== null) {
        window.clearTimeout(timeoutRef.current);
        timeoutRef.current = null;
      }
    }
    if (exchange.status === 'disconnected' && localStatus === 'disconnecting') {
      setLocalStatus('idle');
      if (timeoutRef.current !== null) {
        window.clearTimeout(timeoutRef.current);
        timeoutRef.current = null;
      }
    }
  }, [exchange.status, localStatus]);

  const handleConnect = useCallback(() => {
    setLocalStatus('connecting');
    priceFeedClient.connect(exchange.id).catch((err) => {
      structuredLog('error', `[ExchangeRow] Connect failed for ${exchange.id}: ${String(err)}`);
      onError?.(`Failed to connect to ${exchange.name}`);
    });
    onConnect(exchange.id as ExchangeId);

    // Timeout after 10s
    timeoutRef.current = window.setTimeout(() => {
      setLocalStatus('idle');
      onError?.(`Connection to ${exchange.name} timed out`);
    }, CONNECT_TIMEOUT_MS);
  }, [exchange.id, exchange.name, onConnect, onError]);

  const handleDisconnectClick = useCallback(() => {
    if (!confirmDisconnect) {
      setConfirmDisconnect(true);
      confirmTimeoutRef.current = window.setTimeout(() => {
        setConfirmDisconnect(false);
      }, DISCONNECT_CONFIRM_TIMEOUT_MS);
      return;
    }

    // Confirmed disconnect
    setConfirmDisconnect(false);
    if (confirmTimeoutRef.current !== null) {
      window.clearTimeout(confirmTimeoutRef.current);
      confirmTimeoutRef.current = null;
    }
    setLocalStatus('disconnecting');

    priceFeedClient.disconnect(exchange.id).catch((err) => {
      structuredLog('error', `[ExchangeRow] Disconnect failed for ${exchange.id}: ${String(err)}`);
      onError?.(`Failed to disconnect from ${exchange.name}`);
    });
    onDisconnect(exchange.id as ExchangeId);

    timeoutRef.current = window.setTimeout(() => {
      setLocalStatus('idle');
    }, CONNECT_TIMEOUT_MS);
  }, [exchange.id, exchange.name, confirmDisconnect, onDisconnect, onError]);

  const isTransitioning = localStatus !== 'idle';
  const effectiveStatus = localStatus === 'connecting' ? 'connecting' : exchange.status;

  // Header press handler
  const { pressProps: headerPressProps } = usePress({
    onPress: onToggle,
  });

  // Connect button press handler
  const { pressProps: connectPressProps } = usePress({
    onPress: handleConnect,
    isDisabled: isTransitioning,
  });

  // Disconnect button press handler
  const { pressProps: disconnectPressProps } = usePress({
    onPress: handleDisconnectClick,
    isDisabled: localStatus === 'disconnecting',
  });

  const headerAriaLabel = [
    `${exchange.name}: ${statusLabel}`,
    exchange.messagesPerSecond > 0 ? `${exchange.messagesPerSecond} messages per second` : undefined,
    dqs ? `Data quality: ${Math.round(dqs.score.overall)} out of 100` : undefined,
  ].filter(Boolean).join(', ');

  return (
    <div ref={ref} data-ts-exchange-row="">
      {/* Header row */}
      <div
        data-ts-exchange-row-header=""
        {...headerPressProps}
        role="button"
        tabIndex={0}
        aria-expanded={expanded}
        aria-label={headerAriaLabel}
      >
        <span
          data-ts-exchange-dot=""
          data-status={effectiveStatus}
        />
        <span data-ts-exchange-name="">{exchange.name}</span>
        <Badge
          variant={
            effectiveStatus === 'connected' ? 'success'
              : effectiveStatus === 'connecting' ? 'warning'
                : 'default'
          }
        >
          {localStatus === 'connecting' ? 'connecting' : localStatus === 'disconnecting' ? 'disconnecting' : statusLabel}
        </Badge>

        {needsAuth && (
          <Key size={12} aria-label="API key required" />
        )}

        <span data-ts-exchange-metrics="" aria-live="polite">
          {effectiveStatus === 'connected' && exchange.messagesPerSecond > 0 && (
            <span>{exchange.messagesPerSecond} msg/s</span>
          )}
          {dqs && (
            <span data-ts-dqs-stars="" title={`DQS: ${Math.round(dqs.score.overall)}/100`}>
              {renderStarIcons(dqs.starRating)}
            </span>
          )}
        </span>

        <ChevronDown
          size={14}
          data-ts-exchange-chevron=""
          data-expanded={expanded ? 'true' : 'false'}
        />
      </div>

      {/* Live prices — shown for connected exchanges (even when collapsed) */}
      {effectiveStatus === 'connected' && livePrices.length > 0 && (
        <div data-ts-live-prices="">
          {livePrices.map((lp) => {
            const direction = getDirection(lp.priceChangePercent);
            const stale = isSymbolStale?.(exchange.id as ExchangeId, lp.symbol) ?? false;
            const bidAskTitle = lp.bid !== undefined && lp.ask !== undefined
              ? `Bid: ${formatPrice(lp.bid)} | Ask: ${formatPrice(lp.ask)}`
              : undefined;
            return (
              <span
                key={lp.symbol}
                data-ts-live-price-chip=""
                data-ts-stale={stale ? 'true' : undefined}
                title={bidAskTitle}
              >
                <span data-ts-price-symbol="">{lp.symbol.split('/')[0]}</span>
                <span data-ts-price-type="">{lp.priceType ?? 'last'}</span>
                <span data-ts-price-value="">{formatPrice(lp.price)}</span>
                {lp.bid !== undefined && lp.ask !== undefined && (
                  <span data-ts-price-spread="">
                    {formatSpread(lp.bid, lp.ask)} sprd
                  </span>
                )}
                {lp.priceChangePercent !== undefined && (
                  <span
                    data-ts-price-change=""
                    data-direction={direction}
                  >
                    {formatChange(lp.priceChangePercent)}
                  </span>
                )}
                <span data-ts-price-age="">{formatAge(lp.timestamp)}</span>
              </span>
            );
          })}
        </div>
      )}

      {/* Expanded detail panel */}
      {expanded && (
        <div data-ts-exchange-detail-panel="">
          {/* Metrics grid */}
          {effectiveStatus === 'connected' && (
            <div data-ts-detail-metrics="">
              <div data-ts-detail-metric="">
                <span data-ts-detail-metric-label="">Latency</span>
                <div data-ts-sparkline-row="">
                  <LatencySparkline values={latencyHistory as number[]} width={80} height={18} />
                  <span data-ts-detail-metric-value="">
                    {exchange.latencyMs !== null ? `${exchange.latencyMs}ms` : '--'}
                  </span>
                </div>
              </div>

              <div data-ts-detail-metric="">
                <span data-ts-detail-metric-label="">Uptime</span>
                <span data-ts-detail-metric-value="">
                  {exchange.uptimePercent > 0 ? `${exchange.uptimePercent}%` : '--'}
                </span>
                <div data-ts-uptime-bar-track="">
                  <div
                    data-ts-uptime-bar-fill=""
                    data-quality={exchange.uptimePercent >= 99 ? 'good' : exchange.uptimePercent >= 95 ? 'warning' : 'poor'}
                    style={{ width: `${Math.min(100, exchange.uptimePercent)}%` }}
                  />
                </div>
              </div>

              <div data-ts-detail-metric="">
                <span data-ts-detail-metric-label="">Messages/s</span>
                <span data-ts-detail-metric-value="">{exchange.messagesPerSecond}</span>
              </div>

              <div data-ts-detail-metric="">
                <span data-ts-detail-metric-label="">Circuit Breaker</span>
                <Badge
                  variant={
                    exchange.circuitBreakerState === 'closed' ? 'success'
                      : exchange.circuitBreakerState === 'half-open' ? 'warning'
                        : 'error'
                  }
                >
                  {exchange.circuitBreakerState}
                </Badge>
              </div>
            </div>
          )}

          {/* DQS breakdown (connected only) */}
          {dqs && effectiveStatus === 'connected' && (
            <div data-ts-dqs-inline="">
              <DqsBreakdown score={dqs.score} showWeights />
            </div>
          )}

          {/* Error message */}
          {exchange.lastError !== null && (
            <div
              data-ts-exchange-error=""
              role="alert"
              aria-describedby={`${exchange.id}-error`}
            >
              <span id={`${exchange.id}-error`}>{exchange.lastError}</span>
            </div>
          )}

          {/* Credential form — shown for auth-required exchanges */}
          {AUTH_REQUIRED_EXCHANGES.has(exchange.id) && exchange.status !== 'connected' && (
            <CredentialForm
              exchangeId={exchange.id as ExchangeId}
              onSave={onSaveCredentials}
              onConnect={onConnect}
              onCancel={onToggle}
            />
          )}

          {/* Action buttons */}
          <div data-ts-exchange-actions="">
            {exchange.status === 'connected' ? (
              <Button
                variant="danger"
                size="sm"
                {...disconnectPressProps}
                disabled={localStatus === 'disconnecting'}
                aria-label={confirmDisconnect ? 'Confirm disconnect' : `Disconnect from ${exchange.name}`}
              >
                {confirmDisconnect
                  ? 'Confirm disconnect?'
                  : localStatus === 'disconnecting'
                    ? 'Disconnecting...'
                    : 'Disconnect'}
              </Button>
            ) : !AUTH_REQUIRED_EXCHANGES.has(exchange.id) ? (
              <Button
                variant="primary"
                size="sm"
                {...connectPressProps}
                disabled={isTransitioning}
                aria-label={`Connect to ${exchange.name}`}
              >
                {localStatus === 'connecting' ? 'Connecting...' : 'Connect'}
              </Button>
            ) : null}
          </div>
        </div>
      )}
    </div>
  );
});

ExchangeRow.displayName = 'ExchangeRow';
