import { forwardRef, type CSSProperties, type ReactNode, type ButtonHTMLAttributes } from 'react';

/* -------------------------------------------------------------------------- */
/*  IconButton                                                                */
/*  Square button for toolbar-style icon actions with tooltip.                */
/*  Uses --ts-icon-button-* tokens + ghost/secondary button tokens.           */
/* -------------------------------------------------------------------------- */

type IconButtonVariant = 'ghost' | 'secondary';
type IconButtonSize = 'sm' | 'md' | 'lg';

export interface IconButtonProps extends Omit<ButtonHTMLAttributes<HTMLButtonElement>, 'children'> {
  /** Icon element to render inside the button. */
  icon: ReactNode;
  /** Accessible label, rendered as aria-label and title tooltip. */
  label: string;
  /** Visual style variant. */
  variant?: IconButtonVariant;
  /** Button size controlling width and height (square). */
  size?: IconButtonSize;
  /** Whether the button is visually active (e.g., toggled on). */
  active?: boolean;
}

/* ----- Style injection for hover/active/focus states --------------------- */

const ICON_BUTTON_STYLE_ID = 'ts-icon-button-styles';

function ensureIconButtonStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(ICON_BUTTON_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = ICON_BUTTON_STYLE_ID;
  sheet.textContent = `
    [data-ts-icon-button]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 2px;
    }
    [data-ts-icon-button][data-variant="ghost"]:not(:disabled):hover {
      background: var(--ts-button-ghost-bg-hover);
      color: var(--ts-button-ghost-text-hover);
    }
    [data-ts-icon-button][data-variant="ghost"]:not(:disabled):active {
      background: var(--ts-button-ghost-bg-active);
    }
    [data-ts-icon-button][data-variant="ghost"]:disabled {
      color: var(--ts-button-ghost-text-disabled);
      cursor: not-allowed;
    }
    [data-ts-icon-button][data-variant="secondary"]:not(:disabled):hover {
      background: var(--ts-button-secondary-bg-hover);
    }
    [data-ts-icon-button][data-variant="secondary"]:not(:disabled):active {
      background: var(--ts-button-secondary-bg-active);
    }
    [data-ts-icon-button][data-variant="secondary"]:disabled {
      background: var(--ts-button-secondary-bg-disabled);
      color: var(--ts-button-secondary-text-disabled);
      cursor: not-allowed;
    }
    [data-ts-icon-button][data-active]:not(:disabled) {
      background: var(--ts-accent-subtle);
      color: var(--ts-accent-default);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureIconButtonStyles();
}

/* ----- Variant base styles ----------------------------------------------- */

const VARIANT_STYLES: Record<IconButtonVariant, CSSProperties> = {
  ghost: {
    background: 'var(--ts-button-ghost-bg)',
    color: 'var(--ts-button-ghost-text)',
    border: '1px solid var(--ts-button-ghost-border)',
  },
  secondary: {
    background: 'var(--ts-button-secondary-bg)',
    color: 'var(--ts-button-secondary-text)',
    border: '1px solid var(--ts-button-secondary-border)',
  },
};

const SIZE_STYLES: Record<IconButtonSize, CSSProperties> = {
  sm: {
    width: 'var(--ts-icon-button-size-sm)',
    height: 'var(--ts-icon-button-size-sm)',
  },
  md: {
    width: 'var(--ts-icon-button-size-md)',
    height: 'var(--ts-icon-button-size-md)',
  },
  lg: {
    width: 'var(--ts-icon-button-size-lg)',
    height: 'var(--ts-icon-button-size-lg)',
  },
};

const baseStyle: CSSProperties = {
  all: 'unset',
  display: 'inline-flex',
  alignItems: 'center',
  justifyContent: 'center',
  borderRadius: 'var(--ts-button-radius)',
  cursor: 'pointer',
  flexShrink: 0,
  boxSizing: 'border-box',
  transition: 'background 150ms, color 150ms',
};

export const IconButton = forwardRef<HTMLButtonElement, IconButtonProps>(
  function IconButton(
    { icon, label, variant = 'ghost', size = 'md', active = false, disabled, style, ...rest },
    ref,
  ) {
    return (
      <button
        ref={ref}
        type="button"
        data-ts-icon-button=""
        data-variant={variant}
        {...(active ? { 'data-active': '' } : {})}
        aria-label={label}
        title={label}
        disabled={disabled}
        style={{
          ...baseStyle,
          ...VARIANT_STYLES[variant],
          ...SIZE_STYLES[size],
          ...style,
        }}
        {...rest}
      >
        {icon}
      </button>
    );
  },
);

IconButton.displayName = 'IconButton';
