import type { CSSProperties } from 'react';

/* -------------------------------------------------------------------------- */
/*  FundingRateCell                                                           */
/*  Color-coded funding rate display for DataGrid cells.                      */
/*  Green for positive, red for negative, neutral for zero.                   */
/*  Uses --ts-funding-rate-* tokens.                                          */
/* -------------------------------------------------------------------------- */

export interface FundingRateCellProps {
  /** Funding rate as a decimal (e.g., 0.0001 = 0.01%). */
  rate: number | null;
  /** Whether to show the background color tint. */
  showBackground?: boolean;
  /** Precision for display (default 4). */
  precision?: number;
}

/* ----- Styles ------------------------------------------------------------ */

const baseStyle: CSSProperties = {
  fontFamily: 'var(--ts-funding-rate-cell-font)',
  fontSize: 'var(--ts-funding-rate-cell-font-size)',
  fontVariantNumeric: 'tabular-nums slashed-zero',
  fontFeatureSettings: "'tnum' 1, 'zero' 1",
  textAlign: 'right',
  lineHeight: 1.4,
  padding: '2px 4px',
  borderRadius: 'var(--ts-radius-sm)',
  whiteSpace: 'nowrap',
};

const NEAR_ZERO_THRESHOLD = 0.000005;

function getDirection(rate: number): 'positive' | 'negative' | 'neutral' {
  if (Math.abs(rate) < NEAR_ZERO_THRESHOLD) return 'neutral';
  return rate > 0 ? 'positive' : 'negative';
}

export function FundingRateCell({
  rate,
  showBackground = false,
  precision = 4,
}: FundingRateCellProps): React.JSX.Element {
  if (rate === null) {
    return (
      <span
        data-ts-funding-rate-cell=""
        style={{
          ...baseStyle,
          color: 'var(--ts-funding-rate-neutral-text)',
        }}
      >
        {'\u2014'}
      </span>
    );
  }

  const direction = getDirection(rate);
  const percentage = (rate * 100).toFixed(precision);
  const displayValue = rate > 0 ? `+${percentage}%` : `${percentage}%`;

  const colorMap: Record<string, string> = {
    positive: 'var(--ts-funding-rate-positive-text)',
    negative: 'var(--ts-funding-rate-negative-text)',
    neutral: 'var(--ts-funding-rate-neutral-text)',
  };

  const bgMap: Record<string, string> = {
    positive: 'var(--ts-funding-rate-positive-bg)',
    negative: 'var(--ts-funding-rate-negative-bg)',
    neutral: 'transparent',
  };

  const cellStyle: CSSProperties = {
    ...baseStyle,
    color: colorMap[direction],
    background: showBackground ? bgMap[direction] : 'transparent',
  };

  return (
    <span data-ts-funding-rate-cell="" style={cellStyle}>
      {displayValue}
    </span>
  );
}

FundingRateCell.displayName = 'FundingRateCell';
