import {
  type CSSProperties,
} from 'react';
import { Toolbar, IconButton, Slider } from '../primitives';
import { ColorPicker } from './ColorPicker';
import { LineStylePicker } from './LineStylePicker';
import { LineWidthPicker } from './LineWidthPicker';
import { Settings, Lock, Unlock, Copy, Trash2 } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  DrawingSettingsPanel                                                      */
/*  Floating horizontal toolbar for configuring a selected drawing tool.      */
/*  Uses --ts-toolbar-*, --ts-settings-panel-* tokens.                       */
/* -------------------------------------------------------------------------- */

export interface DrawingSettingsPanelProps {
  /** Current line color. */
  lineColor: string;
  /** Called when line color changes. */
  onLineColorChange: (color: string) => void;
  /** Current line width. */
  lineWidth: number;
  /** Called when line width changes. */
  onLineWidthChange: (width: number) => void;
  /** Current line style. */
  lineStyle: 'solid' | 'dashed' | 'dotted' | 'dash-dot';
  /** Called when line style changes. */
  onLineStyleChange: (style: 'solid' | 'dashed' | 'dotted' | 'dash-dot') => void;
  /** Current fill color (for enclosed shapes). */
  fillColor?: string;
  /** Called when fill color changes. */
  onFillColorChange?: (color: string) => void;
  /** Fill opacity 0–100. */
  fillOpacity?: number;
  /** Called when fill opacity changes. */
  onFillOpacityChange?: (opacity: number) => void;
  /** Whether to show fill controls. */
  showFill?: boolean;
  /** Called when settings gear button is clicked (opens full dialog). */
  onOpenFullSettings?: () => void;
  /** Called when lock button is clicked. */
  onLock?: () => void;
  /** Called when delete button is clicked. */
  onDelete?: () => void;
  /** Called when clone button is clicked. */
  onClone?: () => void;
  /** Whether the drawing is locked. */
  locked?: boolean;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-drawing-settings-styles';

function ensureDrawingSettingsStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-drawing-settings] {
      border-radius: var(--ts-radius-md);
      box-shadow: var(--ts-shadow-md);
    }
    [data-ts-drawing-settings]:focus-within {
      box-shadow: var(--ts-shadow-lg);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureDrawingSettingsStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const panelStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: 'var(--ts-space-1)',
  background: 'var(--ts-toolbar-bg)',
  border: '1px solid var(--ts-toolbar-border)',
  borderRadius: 'var(--ts-radius-md)',
  padding: 'var(--ts-space-1) var(--ts-space-2)',
  boxSizing: 'border-box',
};

const separatorStyle: CSSProperties = {
  width: 1,
  height: 20,
  background: 'var(--ts-toolbar-separator-color)',
  flexShrink: 0,
  margin: '0 var(--ts-space-1)',
};

const fillGroupStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-1)',
};

const fillLabelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
  fontFamily: 'inherit',
  whiteSpace: 'nowrap',
  userSelect: 'none',
};

const opacitySliderStyle: CSSProperties = {
  width: 60,
};

const actionsGroupStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-1)',
};

/* ----- Component --------------------------------------------------------- */

export function DrawingSettingsPanel({
  lineColor,
  onLineColorChange,
  lineWidth,
  onLineWidthChange,
  lineStyle,
  onLineStyleChange,
  fillColor,
  onFillColorChange,
  fillOpacity,
  onFillOpacityChange,
  showFill = false,
  onOpenFullSettings,
  onLock,
  onDelete,
  onClone,
  locked = false,
}: DrawingSettingsPanelProps): React.JSX.Element {

  return (
    <div
      data-ts-drawing-settings=""
      style={panelStyle}
      role="toolbar"
      aria-label="Drawing settings"
      aria-orientation="horizontal"
    >
      {/* Line color */}
      <ColorPicker
        value={lineColor}
        onValueChange={onLineColorChange}
        side="bottom"
        align="start"
      />

      {/* Line width */}
      <LineWidthPicker
        value={lineWidth}
        onValueChange={onLineWidthChange}
      />

      {/* Line style */}
      <LineStylePicker
        value={lineStyle}
        onValueChange={onLineStyleChange}
      />

      {/* Fill controls */}
      {showFill && (
        <>
          <div style={separatorStyle} role="separator" aria-orientation="vertical" />
          <div style={fillGroupStyle} data-ts-drawing-settings-fill="">
            <span style={fillLabelStyle}>Fill</span>
            {fillColor !== undefined && onFillColorChange && (
              <ColorPicker
                value={fillColor}
                onValueChange={onFillColorChange}
                showOpacity={fillOpacity !== undefined}
                opacity={fillOpacity !== undefined ? fillOpacity / 100 : undefined}
                onOpacityChange={onFillOpacityChange ? (v) => onFillOpacityChange(Math.round(v * 100)) : undefined}
                side="bottom"
                align="start"
              />
            )}
          </div>
        </>
      )}

      {/* Separator */}
      <div style={separatorStyle} role="separator" aria-orientation="vertical" />

      {/* Action buttons */}
      <div style={actionsGroupStyle}>
        {onOpenFullSettings && (
          <IconButton
            icon={<Settings size={14} />}
            label="Drawing settings"
            variant="ghost"
            size="sm"
            onClick={onOpenFullSettings}
          />
        )}
        {onLock && (
          <IconButton
            icon={locked ? <Lock size={14} /> : <Unlock size={14} />}
            label={locked ? 'Unlock drawing' : 'Lock drawing'}
            variant="ghost"
            size="sm"
            active={locked}
            onClick={onLock}
          />
        )}
        {onClone && (
          <IconButton
            icon={<Copy size={14} />}
            label="Clone drawing"
            variant="ghost"
            size="sm"
            onClick={onClone}
          />
        )}
        {onDelete && (
          <IconButton
            icon={<Trash2 size={14} />}
            label="Delete drawing"
            variant="ghost"
            size="sm"
            onClick={onDelete}
          />
        )}
      </div>
    </div>
  );
}

DrawingSettingsPanel.displayName = 'DrawingSettingsPanel';
