import type { ExchangeId } from '@deskmodal/data-layer';
import { priceFeedClient } from './price-feed-client';
import type { CommandResult, FeedStatus, FeedStatusExchange } from './price-feed-client';

/* -------------------------------------------------------------------------- */
/*  Feed Manager                                                               */
/*  Thin wrapper over the PriceFeedClient. No WebSocket management — all       */
/*  exchange connectivity is handled by the native price-feed service.          */
/* -------------------------------------------------------------------------- */

/** Represents a managed exchange with its registry metadata and live status. */
export interface ManagedExchange {
  /** Exchange identifier. */
  readonly exchangeId: ExchangeId;
  /** Human-readable display name. */
  readonly displayName: string;
  /** WebSocket URL for display purposes. */
  readonly websocketUrl: string;
  /** Whether this exchange is currently connected (updated from service status). */
  connected: boolean;
}

/** Configuration entry for an exchange in the registry. */
interface ExchangeEntry {
  readonly exchangeId: ExchangeId;
  readonly displayName: string;
  readonly websocketUrl: string;
}

/** Registry of all supported CEX exchanges. */
const EXCHANGE_REGISTRY: ExchangeEntry[] = [
  {
    exchangeId: 'binance',
    displayName: 'Binance',
    websocketUrl: 'wss://stream.binance.us:9443/ws',
  },
  {
    exchangeId: 'coinbase',
    displayName: 'Coinbase',
    websocketUrl: 'wss://ws-feed.exchange.coinbase.com',
  },
  {
    exchangeId: 'bybit',
    displayName: 'Bybit',
    websocketUrl: 'wss://stream.bybit.com/v5/public/spot',
  },
  {
    exchangeId: 'okx',
    displayName: 'OKX',
    websocketUrl: 'wss://ws.okx.com:8443/ws/v5/public',
  },
  {
    exchangeId: 'kraken',
    displayName: 'Kraken',
    websocketUrl: 'wss://ws.kraken.com/v2',
  },
  {
    exchangeId: 'gemini',
    displayName: 'Gemini',
    websocketUrl: 'wss://api.gemini.com/v1/marketdata/BTCUSD',
  },
];

/**
 * Manages exchange registry and delegates all operations to the
 * native price-feed service via FDC3 intents.
 *
 * Singleton within the Feeds app.
 */
export class FeedManager {
  private readonly exchanges: Map<ExchangeId, ManagedExchange>;

  constructor() {
    this.exchanges = new Map();

    for (const entry of EXCHANGE_REGISTRY) {
      this.exchanges.set(entry.exchangeId, {
        exchangeId: entry.exchangeId,
        displayName: entry.displayName,
        websocketUrl: entry.websocketUrl,
        connected: false,
      });
    }
  }

  /** Get all managed exchanges. */
  getExchanges(): ManagedExchange[] {
    return Array.from(this.exchanges.values());
  }

  /** Get a specific managed exchange by ID. */
  getExchange(exchangeId: ExchangeId): ManagedExchange | undefined {
    return this.exchanges.get(exchangeId);
  }

  /** Connect to an exchange via the price-feed service. */
  async connect(exchangeId: ExchangeId): Promise<CommandResult> {
    const result = await priceFeedClient.connect(exchangeId);
    if (result.success) {
      const managed = this.exchanges.get(exchangeId);
      if (managed) {
        managed.connected = true;
      }
    }
    return result;
  }

  /** Disconnect from an exchange via the price-feed service. */
  async disconnect(exchangeId: ExchangeId): Promise<CommandResult> {
    const result = await priceFeedClient.disconnect(exchangeId);
    if (result.success) {
      const managed = this.exchanges.get(exchangeId);
      if (managed) {
        managed.connected = false;
      }
    }
    return result;
  }

  /** Subscribe to a symbol on an exchange via the price-feed service. */
  async subscribe(exchangeId: ExchangeId, symbol: string): Promise<CommandResult> {
    return priceFeedClient.subscribe(exchangeId, symbol);
  }

  /** Unsubscribe from a symbol on an exchange via the price-feed service. */
  async unsubscribe(exchangeId: ExchangeId, symbol: string): Promise<CommandResult> {
    return priceFeedClient.unsubscribe(exchangeId, symbol);
  }

  /** Store credentials for an exchange in the OS keychain. */
  async setCredentials(
    exchangeId: ExchangeId,
    credentials: { apiKey: string; apiSecret: string; passphrase?: string },
  ): Promise<CommandResult> {
    return priceFeedClient.setCredentials(exchangeId, {
      exchange: exchangeId,
      ...credentials,
    });
  }

  /** Query the current status of all exchanges from the service. */
  async getStatus(exchangeId?: string): Promise<FeedStatus> {
    return priceFeedClient.getStatus(exchangeId);
  }

  /**
   * Update local exchange state from a feed status update received
   * on the FDC3 status channel.
   */
  applyStatusUpdate(status: FeedStatus): void {
    for (const ex of status.exchanges) {
      const managed = this.exchanges.get(ex.exchangeId as ExchangeId);
      if (managed) {
        managed.connected = ex.connected;
      }
    }
  }
}

/** Module-level singleton. */
let instance: FeedManager | null = null;

/** Get the shared FeedManager singleton. */
export function getFeedManager(): FeedManager {
  if (!instance) {
    instance = new FeedManager();
  }
  return instance;
}
