import { useState, useCallback, type CSSProperties } from 'react';
import { Input, Select, Button, Dialog } from '@deskmodal/ui-components';
import type { AuthType, CustomRestApiSource } from '../hooks/use-custom-sources';

/* -------------------------------------------------------------------------- */
/*  CustomRestApiForm                                                         */
/*  Form for configuring a custom REST API polling data source.               */
/* -------------------------------------------------------------------------- */

export interface CustomRestApiFormProps {
  /** Whether the dialog is open. */
  readonly open: boolean;
  /** Close the dialog. */
  readonly onOpenChange: (open: boolean) => void;
  /** Called with the completed source config when saved. */
  readonly onSave: (source: Omit<CustomRestApiSource, 'id' | 'createdAt'>) => void;
}

/* ----- Styles ------------------------------------------------------------ */

const formStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: 'var(--ts-space-3)',
  marginTop: 'var(--ts-space-3)',
};

const fieldGroupStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: 'var(--ts-space-1)',
};

const labelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-sm)',
  fontWeight: 500,
  color: 'var(--ts-text-secondary)',
};

const rowStyle: CSSProperties = {
  display: 'flex',
  gap: 'var(--ts-space-2)',
};

const sectionLabelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
  textTransform: 'uppercase',
  letterSpacing: '0.03em',
  marginTop: 'var(--ts-space-2)',
};

const actionsStyle: CSSProperties = {
  display: 'flex',
  justifyContent: 'flex-end',
  gap: 'var(--ts-space-2)',
  marginTop: 'var(--ts-space-2)',
};

/* ----- Select options ---------------------------------------------------- */

const AUTH_OPTIONS = [
  { value: 'none', label: 'None' },
  { value: 'api-key', label: 'API Key (header)' },
  { value: 'basic', label: 'Basic Auth' },
  { value: 'bearer', label: 'Bearer Token' },
  { value: 'custom-header', label: 'Custom Header' },
];

const INTERVAL_OPTIONS = [
  { value: '1000', label: '1 second' },
  { value: '5000', label: '5 seconds' },
  { value: '10000', label: '10 seconds' },
  { value: '30000', label: '30 seconds' },
  { value: '60000', label: '1 minute' },
  { value: '300000', label: '5 minutes' },
];

export function CustomRestApiForm({
  open,
  onOpenChange,
  onSave,
}: CustomRestApiFormProps): React.JSX.Element {
  const [name, setName] = useState('');
  const [url, setUrl] = useState('');
  const [authType, setAuthType] = useState<AuthType>('none');
  const [pollingInterval, setPollingInterval] = useState('5000');
  const [apiKey, setApiKey] = useState('');
  const [apiSecret, setApiSecret] = useState('');
  const [pricePath, setPricePath] = useState('$.price');
  const [volumePath, setVolumePath] = useState('$.volume');
  const [timestampPath, setTimestampPath] = useState('$.timestamp');
  const [symbolPath, setSymbolPath] = useState('$.symbol');

  const isValid = name.trim().length > 0 && url.trim().length > 0;

  const handleSave = useCallback(() => {
    const credentials: Record<string, string> = {};
    if (authType !== 'none') {
      if (apiKey) credentials['apiKey'] = apiKey;
      if (apiSecret) credentials['apiSecret'] = apiSecret;
    }

    onSave({
      type: 'rest-api',
      name: name.trim(),
      url: url.trim(),
      authType,
      credentials,
      pollingIntervalMs: parseInt(pollingInterval, 10),
      fieldMapping: {
        pricePath,
        volumePath,
        timestampPath,
        symbolPath,
      },
    });

    onOpenChange(false);
  }, [name, url, authType, pollingInterval, apiKey, apiSecret, pricePath, volumePath, timestampPath, symbolPath, onSave, onOpenChange]);

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <Dialog.Content>
        <Dialog.Title>Custom REST API Source</Dialog.Title>
        <Dialog.Description>
          Configure a REST endpoint to poll for market data.
        </Dialog.Description>

        <div style={formStyle}>
          <div style={fieldGroupStyle}>
            <label style={labelStyle}>Name</label>
            <Input
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="My REST Feed"
              size="sm"
              style={{ width: '100%' }}
            />
          </div>

          <div style={rowStyle}>
            <div style={{ ...fieldGroupStyle, flex: 1 }}>
              <label style={labelStyle}>API URL</label>
              <Input
                value={url}
                onChange={(e) => setUrl(e.target.value)}
                placeholder="https://api.example.com/v1/ticker"
                size="sm"
                style={{ width: '100%' }}
              />
            </div>
            <div style={fieldGroupStyle}>
              <label style={labelStyle}>Polling Interval</label>
              <Select
                options={INTERVAL_OPTIONS}
                value={pollingInterval}
                onValueChange={setPollingInterval}
                size="sm"
              />
            </div>
          </div>

          <div style={fieldGroupStyle}>
            <label style={labelStyle}>Authentication</label>
            <Select
              options={AUTH_OPTIONS}
              value={authType}
              onValueChange={(v) => setAuthType(v as AuthType)}
              size="sm"
            />
          </div>

          {authType !== 'none' && (
            <div style={rowStyle}>
              <div style={{ ...fieldGroupStyle, flex: 1 }}>
                <label style={labelStyle}>
                  {authType === 'bearer' ? 'Token' : 'API Key'}
                </label>
                <Input
                  value={apiKey}
                  onChange={(e) => setApiKey(e.target.value)}
                  placeholder={authType === 'bearer' ? 'Bearer token...' : 'API key...'}
                  size="sm"
                  type="password"
                  style={{ width: '100%' }}
                />
              </div>
              {authType !== 'bearer' && (
                <div style={{ ...fieldGroupStyle, flex: 1 }}>
                  <label style={labelStyle}>Secret / Password</label>
                  <Input
                    value={apiSecret}
                    onChange={(e) => setApiSecret(e.target.value)}
                    placeholder="Secret..."
                    size="sm"
                    type="password"
                    style={{ width: '100%' }}
                  />
                </div>
              )}
            </div>
          )}

          <span style={sectionLabelStyle}>Response Field Mapping</span>

          <div style={rowStyle}>
            <div style={{ ...fieldGroupStyle, flex: 1 }}>
              <label style={labelStyle}>Price Path</label>
              <Input
                value={pricePath}
                onChange={(e) => setPricePath(e.target.value)}
                placeholder="$.data.price"
                size="sm"
                style={{ width: '100%' }}
              />
            </div>
            <div style={{ ...fieldGroupStyle, flex: 1 }}>
              <label style={labelStyle}>Volume Path</label>
              <Input
                value={volumePath}
                onChange={(e) => setVolumePath(e.target.value)}
                placeholder="$.data.volume"
                size="sm"
                style={{ width: '100%' }}
              />
            </div>
          </div>

          <div style={rowStyle}>
            <div style={{ ...fieldGroupStyle, flex: 1 }}>
              <label style={labelStyle}>Timestamp Path</label>
              <Input
                value={timestampPath}
                onChange={(e) => setTimestampPath(e.target.value)}
                placeholder="$.data.ts"
                size="sm"
                style={{ width: '100%' }}
              />
            </div>
            <div style={{ ...fieldGroupStyle, flex: 1 }}>
              <label style={labelStyle}>Symbol Path</label>
              <Input
                value={symbolPath}
                onChange={(e) => setSymbolPath(e.target.value)}
                placeholder="$.data.symbol"
                size="sm"
                style={{ width: '100%' }}
              />
            </div>
          </div>

          <div style={actionsStyle}>
            <Dialog.Close>
              <Button variant="ghost" size="sm">
                Cancel
              </Button>
            </Dialog.Close>
            <Button
              variant="primary"
              size="sm"
              onClick={handleSave}
              disabled={!isValid}
            >
              Save
            </Button>
          </div>
        </div>
      </Dialog.Content>
    </Dialog>
  );
}

CustomRestApiForm.displayName = 'CustomRestApiForm';
