import { forwardRef, useCallback } from 'react';
import { usePress } from '@react-aria/interactions';
import { AlertTriangle, RefreshCw } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  ServiceUnavailableBanner                                                   */
/*  Displayed when the price-feed service is unreachable. Provides clear       */
/*  messaging and a retry action without blocking the entire UI.               */
/* -------------------------------------------------------------------------- */

export interface ServiceUnavailableBannerProps {
  /** Callback invoked when the user presses the retry button. */
  readonly onRetry: () => void;
  /** Optional error detail to display below the main message. */
  readonly error?: string;
}

/** Inject component styles once. */
let stylesInjected = false;

function ensureServiceUnavailableBannerStyles(): void {
  if (stylesInjected) return;
  stylesInjected = true;

  const css = `
[data-ts-service-unavailable-banner] {
  display: flex;
  flex-direction: column;
  align-items: center;
  justify-content: center;
  gap: var(--ts-space-3);
  padding: var(--ts-space-6, 24px) var(--ts-space-4, 16px);
  background: var(--ts-surface-secondary, var(--ts-panel-bg));
  border-bottom: 1px solid var(--ts-panel-border);
  text-align: center;
}

[data-ts-service-unavailable-banner] [data-ts-banner-icon] {
  color: var(--ts-status-error, #ef4444);
  flex-shrink: 0;
}

[data-ts-service-unavailable-banner] [data-ts-banner-title] {
  font-size: var(--ts-font-md);
  font-weight: 600;
  color: var(--ts-text-primary);
  line-height: 1.3;
}

[data-ts-service-unavailable-banner] [data-ts-banner-error] {
  font-size: var(--ts-font-xs);
  color: var(--ts-text-tertiary);
  max-width: 400px;
  word-break: break-word;
}

[data-ts-service-unavailable-banner] [data-ts-banner-retry] {
  display: inline-flex;
  align-items: center;
  gap: var(--ts-space-2, 8px);
  padding: var(--ts-space-2, 8px) var(--ts-space-4, 16px);
  background: var(--ts-surface-accent, var(--ts-status-info, #3b82f6));
  color: var(--ts-text-on-accent, #ffffff);
  border: none;
  border-radius: var(--ts-radius-sm);
  cursor: pointer;
  font-size: var(--ts-font-sm);
  font-weight: 500;
  transition: opacity 150ms;
  user-select: none;
}

[data-ts-service-unavailable-banner] [data-ts-banner-retry]:hover {
  opacity: 0.9;
}

[data-ts-service-unavailable-banner] [data-ts-banner-retry]:focus-visible {
  outline: 2px solid var(--ts-focus-ring, #3b82f6);
  outline-offset: 2px;
}
`;

  const style = document.createElement('style');
  style.setAttribute('data-ts-component', 'service-unavailable-banner');
  style.textContent = css;
  document.head.appendChild(style);
}

export const ServiceUnavailableBanner = forwardRef<HTMLDivElement, ServiceUnavailableBannerProps>(
  function ServiceUnavailableBanner({ onRetry, error }, ref) {
    ensureServiceUnavailableBannerStyles();

    const handleRetry = useCallback(() => {
      onRetry();
    }, [onRetry]);

    const { pressProps } = usePress({
      onPress: handleRetry,
    });

    return (
      <div
        ref={ref}
        data-ts-service-unavailable-banner=""
        role="alert"
        aria-live="polite"
      >
        <AlertTriangle
          size={24}
          data-ts-banner-icon=""
          aria-hidden="true"
        />

        <span data-ts-banner-title="">
          Price Feed service is not available
        </span>

        {error && (
          <span data-ts-banner-error="">
            {error}
          </span>
        )}

        <button
          data-ts-banner-retry=""
          {...pressProps}
          type="button"
          aria-label="Retry connecting to Price Feed service"
        >
          <RefreshCw size={14} aria-hidden="true" />
          Retry
        </button>
      </div>
    );
  },
);

ServiceUnavailableBanner.displayName = 'ServiceUnavailableBanner';
