import {
  forwardRef,
  useRef,
  useState,
  useEffect,
  useCallback,
  useMemo,
  type CSSProperties,
  type ReactNode,
  type KeyboardEvent as ReactKeyboardEvent,
} from 'react';
import { Search, Loader2 } from 'lucide-react';
import { ScrollArea } from '../primitives/ScrollArea';

/* -------------------------------------------------------------------------- */
/*  CommandPalette                                                             */
/*  Shared command palette / symbol search overlay triggered by Ctrl+K.       */
/*  520px wide, centered, 80px from top. Dark overlay, keyboard navigation,   */
/*  150ms debounce, category grouping, VirtualList for performance.           */
/*  Uses --ts-* CSS custom properties, data-ts-* attributes.                  */
/* -------------------------------------------------------------------------- */

/* ----- Types -------------------------------------------------------------- */

export interface CommandPaletteResult {
  id: string;
  label: string;
  description?: string;
  category?: string;
  icon?: ReactNode;
  /** Keyboard shortcut hint displayed as a <kbd> element, right-aligned. */
  shortcut?: string;
}

export interface CommandPaletteProps {
  /** Whether the palette is open */
  open: boolean;
  /** Callback when palette should close */
  onClose: () => void;
  /** Search handler - called with debounced query */
  onSearch: (query: string) => void;
  /** Search results to display */
  results: CommandPaletteResult[];
  /** Called when a result is selected */
  onSelect: (result: CommandPaletteResult) => void;
  /** Placeholder text */
  placeholder?: string;
  /** Whether search is loading */
  isLoading?: boolean;
  /** Items shown when query is empty (recent/frequent). Replaces "Type to search". */
  recentItems?: CommandPaletteResult[];
  /** When true, calls onSearch immediately without debounce (for synchronous providers). */
  immediateSearch?: boolean;
}

/* ----- Style injection --------------------------------------------------- */

const COMMAND_PALETTE_STYLE_ID = 'ts-command-palette-styles';

function ensureCommandPaletteStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(COMMAND_PALETTE_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = COMMAND_PALETTE_STYLE_ID;
  sheet.textContent = `
    @keyframes ts-command-palette-overlay-in {
      from { opacity: 0; }
      to { opacity: 1; }
    }
    @keyframes ts-command-palette-overlay-out {
      from { opacity: 1; }
      to { opacity: 0; }
    }
    @keyframes ts-command-palette-content-in {
      from { opacity: 0; transform: translateY(-8px); }
      to { opacity: 1; transform: translateY(0); }
    }
    [data-ts-command-palette-overlay] {
      animation: ts-command-palette-overlay-in 150ms ease-out;
    }
    [data-ts-command-palette-content] {
      animation: ts-command-palette-content-in 150ms ease-out;
    }
    [data-ts-command-palette-input]::placeholder {
      color: var(--ts-text-tertiary);
    }
    [data-ts-command-palette-item][data-active] {
      background: var(--ts-menu-item-bg-hover);
    }
    [data-ts-command-palette-item]:hover {
      background: var(--ts-menu-item-bg-hover);
    }
    @keyframes ts-command-palette-spin {
      from { transform: rotate(0deg); }
      to { transform: rotate(360deg); }
    }
    [data-ts-command-palette-spinner] {
      animation: ts-command-palette-spin 750ms linear infinite;
    }
    @media (prefers-reduced-motion: reduce) {
      [data-ts-command-palette-overlay],
      [data-ts-command-palette-content] {
        animation: none;
      }
      [data-ts-command-palette-spinner] {
        animation: none;
      }
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureCommandPaletteStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const overlayStyle: CSSProperties = {
  position: 'fixed',
  inset: 0,
  background: 'rgba(0, 0, 0, 0.5)',
  zIndex: 100,
};

const contentStyle: CSSProperties = {
  position: 'fixed',
  top: 80,
  left: '50%',
  transform: 'translateX(-50%)',
  width: 520,
  maxWidth: 'calc(100vw - 32px)',
  background: 'var(--ts-panel-bg, #1e1e2e)',
  border: '1px solid var(--ts-panel-border, #333)',
  borderRadius: 'var(--ts-radius-lg, 12px)',
  boxShadow: '0 16px 48px rgba(0, 0, 0, 0.4)',
  zIndex: 101,
  display: 'flex',
  flexDirection: 'column',
  maxHeight: 'calc(100% - 160px)',
  overflow: 'hidden',
  boxSizing: 'border-box',
  fontFamily: 'inherit',
};

const inputContainerStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2, 8px)',
  padding: '12px 16px',
  borderBottom: '1px solid var(--ts-panel-border, #333)',
  flexShrink: 0,
};

const searchIconStyle: CSSProperties = {
  color: 'var(--ts-text-tertiary)',
  flexShrink: 0,
  display: 'flex',
  alignItems: 'center',
};

const inputFieldStyle: CSSProperties = {
  all: 'unset',
  flex: 1,
  minWidth: 0,
  fontSize: 'var(--ts-font-md, 14px)',
  fontFamily: 'inherit',
  color: 'var(--ts-text-primary)',
  lineHeight: 1.5,
};

const spinnerStyle: CSSProperties = {
  color: 'var(--ts-text-tertiary)',
  flexShrink: 0,
  display: 'flex',
  alignItems: 'center',
};

const resultsContainerStyle: CSSProperties = {
  flex: 1,
  minHeight: 0,
  overflow: 'hidden',
};

const emptyStyle: CSSProperties = {
  padding: '24px 16px',
  textAlign: 'center',
  fontSize: 'var(--ts-font-sm, 12px)',
  color: 'var(--ts-text-tertiary)',
};

const categoryHeaderStyle: CSSProperties = {
  padding: '8px 16px 4px',
  fontSize: 'var(--ts-font-xs, 11px)',
  fontWeight: 600,
  color: 'var(--ts-text-tertiary)',
  textTransform: 'uppercase',
  letterSpacing: '0.05em',
  userSelect: 'none',
};

const itemStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2, 8px)',
  padding: '8px 16px',
  cursor: 'pointer',
  transition: 'background 80ms',
  userSelect: 'none',
};

const itemIconStyle: CSSProperties = {
  flexShrink: 0,
  color: 'var(--ts-text-tertiary)',
  display: 'flex',
  alignItems: 'center',
};

const itemLabelStyle: CSSProperties = {
  flex: 1,
  minWidth: 0,
  display: 'flex',
  flexDirection: 'column',
  gap: 2,
};

const itemLabelTextStyle: CSSProperties = {
  fontSize: 'var(--ts-font-md, 14px)',
  color: 'var(--ts-text-primary)',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  whiteSpace: 'nowrap',
};

const itemDescriptionStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs, 11px)',
  color: 'var(--ts-text-tertiary)',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  whiteSpace: 'nowrap',
};

const kbdHintStyle: CSSProperties = {
  flexShrink: 0,
  fontSize: 'var(--ts-font-xs, 11px)',
  color: 'var(--ts-text-tertiary)',
  padding: '2px 6px',
  borderRadius: 'var(--ts-radius-sm, 4px)',
  background: 'var(--ts-surface-2, rgba(255,255,255,0.06))',
  border: '1px solid var(--ts-panel-border, #333)',
  fontFamily: 'inherit',
};

/* ----- Flattened list item types ----------------------------------------- */

interface FlatCategoryHeader {
  type: 'category';
  id: string;
  label: string;
}

interface FlatResultItem {
  type: 'result';
  result: CommandPaletteResult;
  flatIndex: number; // Index among result items only (for active tracking)
}

type FlatItem = FlatCategoryHeader | FlatResultItem;

const DEBOUNCE_MS = 150;
const MAX_VISIBLE_HEIGHT = 360;

/* ----- Component --------------------------------------------------------- */

export const CommandPalette = forwardRef<HTMLDivElement, CommandPaletteProps>(
  function CommandPalette(
    {
      open,
      onClose,
      onSearch,
      results,
      onSelect,
      placeholder = 'Search symbols, commands...',
      isLoading = false,
      recentItems,
      immediateSearch = false,
    },
    ref,
  ) {
    const inputRef = useRef<HTMLInputElement>(null);
    const containerRef = useRef<HTMLDivElement>(null);
    const [query, setQuery] = useState('');
    const [activeIndex, setActiveIndex] = useState(0);
    const debounceRef = useRef<ReturnType<typeof setTimeout> | null>(null);

    // Determine which items to display: results when query non-empty, recent otherwise
    const displayItems = useMemo(() => {
      if (query.length > 0) return results;
      return recentItems ?? [];
    }, [query, results, recentItems]);

    // Build flat list with category headers
    const { flatItems, resultItems } = useMemo(() => {
      const flat: FlatItem[] = [];
      const resultOnly: CommandPaletteResult[] = [];
      let currentCategory: string | undefined;
      let resultIdx = 0;

      for (const result of displayItems) {
        if (result.category !== currentCategory) {
          currentCategory = result.category;
          if (currentCategory !== undefined) {
            const headerLabel = query.length === 0 && recentItems && recentItems.length > 0
              ? `Recent — ${currentCategory}`
              : currentCategory;
            flat.push({ type: 'category', id: `cat-${currentCategory}`, label: headerLabel });
          }
        }
        flat.push({ type: 'result', result, flatIndex: resultIdx });
        resultOnly.push(result);
        resultIdx++;
      }

      return { flatItems: flat, resultItems: resultOnly };
    }, [displayItems, query.length, recentItems]);

    // Reset active index when results change
    useEffect(() => {
      setActiveIndex(0);
    }, [results]);

    // Reset query when opening
    useEffect(() => {
      if (open) {
        setQuery('');
        setActiveIndex(0);
      }
    }, [open]);

    // Focus input when palette opens
    useEffect(() => {
      if (open) {
        // Use requestAnimationFrame to ensure DOM is ready
        const frame = requestAnimationFrame(() => {
          inputRef.current?.focus();
        });
        return () => cancelAnimationFrame(frame);
      }
    }, [open]);

    // Close on Escape at document level
    useEffect(() => {
      if (!open) return;

      function handleGlobalKeyDown(e: globalThis.KeyboardEvent): void {
        if (e.key === 'Escape') {
          e.preventDefault();
          e.stopPropagation();
          onClose();
        }
      }

      document.addEventListener('keydown', handleGlobalKeyDown, true);
      return () => document.removeEventListener('keydown', handleGlobalKeyDown, true);
    }, [open, onClose]);

    // Debounced search (or immediate when immediateSearch is true)
    const handleInputChange = useCallback(
      (value: string) => {
        setQuery(value);
        if (debounceRef.current !== null) {
          clearTimeout(debounceRef.current);
        }
        if (immediateSearch) {
          onSearch(value);
        } else {
          debounceRef.current = setTimeout(() => {
            onSearch(value);
          }, DEBOUNCE_MS);
        }
      },
      [onSearch, immediateSearch],
    );

    // Cleanup debounce on unmount
    useEffect(() => {
      return () => {
        if (debounceRef.current !== null) {
          clearTimeout(debounceRef.current);
        }
      };
    }, []);

    // Keyboard navigation
    const handleKeyDown = useCallback(
      (e: ReactKeyboardEvent<HTMLInputElement>) => {
        const count = resultItems.length;
        if (count === 0) return;

        switch (e.key) {
          case 'ArrowDown': {
            e.preventDefault();
            setActiveIndex((prev) => (prev + 1) % count);
            break;
          }
          case 'ArrowUp': {
            e.preventDefault();
            setActiveIndex((prev) => (prev - 1 + count) % count);
            break;
          }
          case 'Enter': {
            e.preventDefault();
            const selected = resultItems[activeIndex];
            if (selected !== undefined) {
              onSelect(selected);
            }
            break;
          }
          // Escape handled by document-level listener
        }
      },
      [resultItems, activeIndex, onSelect],
    );

    // Overlay click closes palette
    const handleOverlayClick = useCallback(() => {
      onClose();
    }, [onClose]);

    // Prevent content click from closing
    const handleContentClick = useCallback((e: React.MouseEvent) => {
      e.stopPropagation();
    }, []);

    if (!open) return null;

    return (
      <>
        {/* Overlay */}
        <div
          data-ts-command-palette-overlay=""
          style={overlayStyle}
          onClick={handleOverlayClick}
          aria-hidden
        />

        {/* Content */}
        <div
          ref={ref}
          data-ts-command-palette-content=""
          role="dialog"
          aria-label="Command palette"
          aria-modal="true"
          style={contentStyle}
          onClick={handleContentClick}
        >
          {/* Search input */}
          <div style={inputContainerStyle}>
            <span style={searchIconStyle} aria-hidden>
              <Search size={16} />
            </span>
            <input
              ref={inputRef}
              data-ts-command-palette-input=""
              type="text"
              value={query}
              onChange={(e) => handleInputChange(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder={placeholder}
              style={inputFieldStyle}
              role="combobox"
              aria-expanded={resultItems.length > 0}
              aria-controls="ts-command-palette-results"
              aria-activedescendant={
                resultItems.length > 0
                  ? `ts-command-palette-item-${activeIndex}`
                  : undefined
              }
              aria-autocomplete="list"
              autoComplete="off"
              spellCheck={false}
            />
            {isLoading && (
              <span data-ts-command-palette-spinner="" style={spinnerStyle} aria-hidden>
                <Loader2 size={16} />
              </span>
            )}
            <span style={kbdHintStyle} aria-hidden>
              ESC
            </span>
          </div>

          {/* Results */}
          <div
            id="ts-command-palette-results"
            role="listbox"
            aria-label="Search results"
            style={resultsContainerStyle}
            ref={containerRef}
          >
            {resultItems.length === 0 && query.length > 0 && !isLoading && (
              <div style={emptyStyle}>No results found</div>
            )}
            {resultItems.length === 0 && query.length === 0 && !recentItems && (
              <div style={emptyStyle}>Type to search</div>
            )}
            {resultItems.length === 0 && query.length === 0 && recentItems && recentItems.length === 0 && (
              <div style={emptyStyle}>No recent items</div>
            )}
            {flatItems.length > 0 && (
              <div style={{ maxHeight: MAX_VISIBLE_HEIGHT, overflow: 'hidden' }}>
                <ScrollArea>
                  <div data-ts-command-palette-list="">
                  {flatItems.map((item) => {
                    if (item.type === 'category') {
                      return (
                        <div
                          key={item.id}
                          data-ts-command-palette-category=""
                          style={categoryHeaderStyle}
                          aria-hidden
                        >
                          {item.label}
                        </div>
                      );
                    }

                    const { result, flatIndex } = item;
                    const isActive = flatIndex === activeIndex;

                    return (
                      <div
                        key={result.id}
                        id={`ts-command-palette-item-${flatIndex}`}
                        data-ts-command-palette-item=""
                        {...(isActive ? { 'data-active': '' } : {})}
                        role="option"
                        aria-selected={isActive}
                        style={itemStyle}
                        onClick={() => onSelect(result)}
                        onMouseEnter={() => setActiveIndex(flatIndex)}
                      >
                        {result.icon !== undefined && (
                          <span style={itemIconStyle} aria-hidden>
                            {result.icon}
                          </span>
                        )}
                        <span style={itemLabelStyle}>
                          <span style={itemLabelTextStyle}>{result.label}</span>
                          {result.description !== undefined && (
                            <span style={itemDescriptionStyle}>{result.description}</span>
                          )}
                        </span>
                        {result.shortcut !== undefined && (
                          <kbd style={kbdHintStyle} aria-hidden>
                            {result.shortcut}
                          </kbd>
                        )}
                      </div>
                    );
                  })}
                  </div>
                </ScrollArea>
              </div>
            )}
          </div>
        </div>
      </>
    );
  },
);

CommandPalette.displayName = 'CommandPalette';
