import { useState, useEffect } from 'react';
import type { ExchangeId } from '@deskmodal/data-layer';
import type { Context } from '@deskmodal/fdc3';
import { isDeskmodalQuote, CONTEXT_TYPES } from '@deskmodal/fdc3';
import { onPriceUpdate } from '../services/feed-service';

/* -------------------------------------------------------------------------- */
/*  useLivePrices                                                              */
/*  Event-driven hook -- listens on the FDC3 prices channel for updates.       */
/*  No polling. Accumulates latest ticks in a Map keyed by exchangeId:symbol.  */
/* -------------------------------------------------------------------------- */

/** Throttle interval for flushing accumulated price updates to React state. */
const PRICE_FLUSH_INTERVAL_MS = 200;

/** Live price data for a single symbol on a single exchange. */
export interface LivePrice {
  readonly exchangeId: ExchangeId;
  readonly symbol: string;
  readonly price: number;
  readonly bid?: number;
  readonly ask?: number;
  readonly spread?: number;
  readonly priceChangePercent: number | undefined;
  readonly volume24h: number;
  readonly timestamp: number;
  readonly priceType?: 'last' | 'vwap' | 'mid';
}

/** Live prices grouped by exchange. */
export type LivePricesByExchange = ReadonlyMap<ExchangeId, LivePrice[]>;

/** Structured log helper -- routes to DeskModal logging if available. */
function structuredLog(level: 'error' | 'warn' | 'info', message: string): void {
  const win = window as { deskmodal?: { log?: (level: string, msg: string) => void } };
  if (win.deskmodal?.log) {
    win.deskmodal.log(level, message);
  }
}

/**
 * Extract price data from either the new deskmodal.quote format
 * or the legacy fdc3.instrument + deskmodal.aggregation format.
 *
 * Safety net during migration -- remove legacy path after atomic
 * deployment is confirmed.
 */
function extractPriceFromContext(context: Context): LivePrice | null {
  // -- New format: deskmodal.quote with top-level fields --
  if (isDeskmodalQuote(context)) {
    return {
      exchangeId: (context.exchange ?? 'unknown') as ExchangeId,
      symbol: context.id.ticker,
      price: context.last,
      bid: context.bid,
      ask: context.ask,
      spread: context.spread,
      priceChangePercent: context.changePercent24h,
      volume24h: context.volume24h ?? 0,
      timestamp: context.timestamp,
      priceType: context.priceType,
    };
  }

  // -- Legacy format fallback: fdc3.instrument + nested aggregation --
  const ticker = context.id?.ticker;
  if (!ticker) return null;

  const ctxAny = context as unknown as Record<string, unknown>;
  const agg = ctxAny['deskmodal.aggregation'] as {
    vwapPrice?: number;
    timestamp?: number;
    sources?: Array<{
      price?: number;
      volume24h?: number;
      bid?: number;
      ask?: number;
      exchange?: string;
    }>;
  } | undefined;

  if (agg?.sources && agg.sources.length > 0) {
    const source = agg.sources[0]!;
    const exchangeId = (source.exchange ?? 'unknown') as ExchangeId;
    structuredLog(
      'warn',
      `[use-live-prices] Received legacy fdc3.instrument context for ${ticker} -- migration incomplete`,
    );
    const bid = source.bid;
    const ask = source.ask;
    const spread = bid !== undefined && ask !== undefined && ask > bid ? ask - bid : undefined;
    return {
      exchangeId,
      symbol: ticker,
      price: source.price ?? agg.vwapPrice ?? 0,
      bid,
      ask,
      spread,
      priceChangePercent: undefined,
      volume24h: source.volume24h ?? 0,
      timestamp: agg.timestamp ?? Date.now(),
    };
  }

  // -- Direct field fallback (Phase 8 flat format with old type) --
  const exchangeId = ((ctxAny['exchangeId'] as string | undefined) ?? (ctxAny['exchange'] as string | undefined) ?? 'unknown') as ExchangeId;
  const price = (ctxAny['price'] as number | undefined) ?? (ctxAny['last'] as number | undefined) ?? 0;
  if (price === 0) return null;

  return {
    exchangeId,
    symbol: ticker,
    price,
    bid: ctxAny['bid'] as number | undefined,
    ask: ctxAny['ask'] as number | undefined,
    spread: ctxAny['spread'] as number | undefined,
    priceChangePercent: (ctxAny['changePercent24h'] as number | undefined) ?? (ctxAny['priceChangePercent'] as number | undefined),
    volume24h: (ctxAny['volume24h'] as number | undefined) ?? 0,
    timestamp: (ctxAny['timestamp'] as number | undefined) ?? Date.now(),
  };
}

/**
 * Hook that listens for price updates on the FDC3 prices channel
 * and returns them grouped by exchange for display in the UI.
 *
 * Purely event-driven -- no polling.
 */
export function useLivePrices(): LivePricesByExchange {
  const [pricesByExchange, setPricesByExchange] = useState<Map<ExchangeId, LivePrice[]>>(
    new Map(),
  );

  useEffect(() => {
    // Accumulate latest ticks keyed by exchangeId:symbol in a ref (not state)
    // to avoid triggering re-renders on every single tick.
    const latestTicks = new Map<string, LivePrice>();
    let dirty = false;

    function flush() {
      if (!dirty) return;
      dirty = false;

      // Rebuild grouped map from accumulated ticks
      const grouped = new Map<ExchangeId, LivePrice[]>();
      for (const tick of latestTicks.values()) {
        const existing = grouped.get(tick.exchangeId) ?? [];
        existing.push(tick);
        grouped.set(tick.exchangeId, existing);
      }

      // Sort each exchange's prices by symbol for stable ordering
      for (const prices of grouped.values()) {
        prices.sort((a, b) => a.symbol.localeCompare(b.symbol));
      }

      setPricesByExchange(grouped);
    }

    // Flush at ~5fps (PRICE_FLUSH_INTERVAL_MS) instead of every tick to prevent
    // render storms from high-frequency crypto price updates.
    const intervalId = window.setInterval(flush, PRICE_FLUSH_INTERVAL_MS);

    const unsubscribe = onPriceUpdate((context: Context) => {
      const livePrice = extractPriceFromContext(context);
      if (!livePrice) return;

      const key = `${livePrice.exchangeId}:${livePrice.symbol}`;
      latestTicks.set(key, livePrice);
      dirty = true;
    });

    return () => {
      unsubscribe();
      window.clearInterval(intervalId);
    };
  }, []);

  return pricesByExchange;
}
