import { useCallback, type CSSProperties, type KeyboardEvent } from 'react';
import { ChevronDown, ChevronRight } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  WatchlistSectionHeader                                                     */
/*  Collapsible section divider in watchlist with label and symbol count.       */
/*  Uses --ts-watchlist-section-* tokens.                                       */
/* -------------------------------------------------------------------------- */

export interface WatchlistSectionHeaderProps {
  /** Section label, e.g., "CRYPTO", "FOREX", "My Favorites". */
  label: string;
  /** Number of symbols in the section. */
  count: number;
  /** Whether the section is collapsed. */
  collapsed: boolean;
  /** Called when collapse state is toggled. */
  onToggle: () => void;
  /** Whether the section is a drag target (currently being dragged over). */
  dragOver?: boolean;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-watchlist-section-styles';

function ensureWatchlistSectionStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-watchlist-section]:hover {
      background: var(--ts-watchlist-row-bg-hover);
    }
    [data-ts-watchlist-section]:focus-visible {
      outline: 2px solid var(--ts-accent-default);
      outline-offset: -2px;
    }
    [data-ts-watchlist-section][data-drag-over] {
      border-bottom: 2px solid var(--ts-accent-default);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureWatchlistSectionStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const rowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  height: 'var(--ts-watchlist-section-height)',
  padding: '0 var(--ts-watchlist-row-padding-x)',
  background: 'var(--ts-watchlist-section-bg)',
  cursor: 'pointer',
  userSelect: 'none',
  gap: 'var(--ts-space-2)',
  boxSizing: 'border-box',
  transition: 'background 100ms',
};

const chevronStyle: CSSProperties = {
  flexShrink: 0,
  color: 'var(--ts-watchlist-section-text)',
};

const labelStyle: CSSProperties = {
  flex: 1,
  color: 'var(--ts-watchlist-section-text)',
  fontSize: 'var(--ts-watchlist-section-font-size)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  textTransform: 'uppercase',
  letterSpacing: '0.05em',
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  whiteSpace: 'nowrap',
};

const countStyle: CSSProperties = {
  flexShrink: 0,
  color: 'var(--ts-watchlist-section-count-text)',
  fontSize: 'var(--ts-watchlist-section-font-size)',
  fontVariantNumeric: 'tabular-nums',
};

/* ----- Component --------------------------------------------------------- */

export function WatchlistSectionHeader({
  label,
  count,
  collapsed,
  onToggle,
  dragOver = false,
}: WatchlistSectionHeaderProps): React.JSX.Element {
  const handleKeyDown = useCallback(
    (event: KeyboardEvent<HTMLDivElement>) => {
      if (event.key === 'Enter' || event.key === ' ') {
        event.preventDefault();
        onToggle();
      }
    },
    [onToggle],
  );

  return (
    <div
      data-ts-watchlist-section=""
      {...(dragOver ? { 'data-drag-over': '' } : {})}
      style={rowStyle}
      role="button"
      tabIndex={0}
      aria-expanded={!collapsed}
      onClick={onToggle}
      onKeyDown={handleKeyDown}
      data-testid="watchlist-section-header"
    >
      <span style={chevronStyle} aria-hidden="true">
        {collapsed ? <ChevronRight size={14} /> : <ChevronDown size={14} />}
      </span>
      <span style={labelStyle} data-testid="watchlist-section-label">{label}</span>
      <span style={countStyle} data-testid="watchlist-section-count">{count}</span>
    </div>
  );
}

WatchlistSectionHeader.displayName = 'WatchlistSectionHeader';
