import { useEffect, useRef } from 'react';
import { getDeskModalAPI } from '@deskmodal/fdc3';

/** Widget IDs used for DeskModal toolbar registration. */
const DQS_WIDGET_ID = 'feeds-dqs-score';
const HEALTH_WIDGET_ID = 'feeds-connection-health';

/** App identifier for the feeds app. */
const APP_ID = 'feeds';

/**
 * Hook that registers and updates DQS score and connection health
 * widgets in the DeskModal toolbar.
 *
 * - DQS score widget: displayed on the right side of the toolbar
 * - Connection health widget: displayed on the left side of the toolbar
 *
 * No-op when DeskModal is not available.
 *
 * @param dqsScore       Aggregate DQS overall score (0-100).
 * @param connectionHealth  Summary string for connection health (e.g., "3/5 connected").
 */
export function useToolbarWidgets(
  dqsScore: number,
  connectionHealth: string,
): void {
  const registeredRef = useRef(false);
  const prevDqsRef = useRef<number | null>(null);
  const prevHealthRef = useRef<string | null>(null);

  /** Register widgets on mount. */
  useEffect(() => {
    const api = getDeskModalAPI();
    if (!api?.toolbar) {
      return;
    }

    Promise.all([
      api.toolbar.registerWidget(APP_ID, DQS_WIDGET_ID, {
        type: 'Label',
        position: 'Right',
        label: 'DQS',
        value: String(dqsScore),
        enabled: true,
      }),
      api.toolbar.registerWidget(APP_ID, HEALTH_WIDGET_ID, {
        type: 'Label',
        position: 'Left',
        label: 'Feeds',
        value: connectionHealth,
        enabled: true,
      }),
    ])
      .then(() => {
        registeredRef.current = true;
        prevDqsRef.current = dqsScore;
        prevHealthRef.current = connectionHealth;
      })
      .catch(() => {
        // Registration failure — degrade silently
      });
    // Only register once on mount
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []);

  /** Update DQS widget when score changes. */
  useEffect(() => {
    if (!registeredRef.current) return;
    if (prevDqsRef.current === dqsScore) return;

    const api = getDeskModalAPI();
    if (!api?.toolbar) return;

    prevDqsRef.current = dqsScore;
    api.toolbar
      .updateWidget(APP_ID, DQS_WIDGET_ID, { value: String(dqsScore) })
      .catch(() => {
        // Update failure — degrade silently
      });
  }, [dqsScore]);

  /** Update connection health widget when status changes. */
  useEffect(() => {
    if (!registeredRef.current) return;
    if (prevHealthRef.current === connectionHealth) return;

    const api = getDeskModalAPI();
    if (!api?.toolbar) return;

    prevHealthRef.current = connectionHealth;
    api.toolbar
      .updateWidget(APP_ID, HEALTH_WIDGET_ID, { value: connectionHealth })
      .catch(() => {
        // Update failure — degrade silently
      });
  }, [connectionHealth]);
}
