import type { CSSProperties } from 'react';
import { formatPrice, formatCompactNumber } from './format-number';

/* -------------------------------------------------------------------------- */
/*  StatusLine                                                                */
/*  OHLCV values overlay for chart.                                           */
/*  Uses --ts-status-line-* tokens.                                           */
/* -------------------------------------------------------------------------- */

export interface StatusLineProps {
  /** Open price (null = awaiting data). */
  open: number | null;
  /** High price (null = awaiting data). */
  high: number | null;
  /** Low price (null = awaiting data). */
  low: number | null;
  /** Close price (null = awaiting data). */
  close: number | null;
  /** Volume (null = awaiting data). */
  volume: number | null;
  /** Previous close price for direction coloring. */
  previousClose: number | null;
  /** Decimal places for price display. */
  precision?: number;
  /** Symbol label shown before OHLCV, e.g. "BTCUSDT". */
  symbol?: string;
  /** Whether the data feeding this status line is stale. */
  stale?: boolean;
}

/* ----- Styles ------------------------------------------------------------ */

const containerStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: 'var(--ts-status-line-gap)',
  fontFamily: 'var(--ts-status-line-font)',
  fontSize: 'var(--ts-status-line-font-size)',
  fontVariantNumeric: 'tabular-nums',
  background: 'var(--ts-status-line-bg)',
  padding: 'var(--ts-status-line-padding)',
  lineHeight: 1.4,
  flexWrap: 'wrap',
};

const labelStyle: CSSProperties = {
  color: 'var(--ts-status-line-label-text)',
  userSelect: 'none',
};

const valueStyle: CSSProperties = {
  color: 'var(--ts-status-line-value-text)',
};

const symbolStyle: CSSProperties = {
  color: 'var(--ts-status-line-value-text)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  marginRight: '4px',
};

const staleTagStyle: CSSProperties = {
  color: 'var(--ts-status-warning, #f59e0b)',
  fontSize: 'var(--ts-status-line-font-size)',
  fontWeight: 500,
  marginLeft: '4px',
  userSelect: 'none',
};

/* ----- Direction helpers ------------------------------------------------- */

function getCloseColor(close: number | null, previousClose: number | null): string {
  if (close == null || previousClose == null) return 'var(--ts-status-line-value-text)';
  if (close > previousClose) return 'var(--ts-price-up-text)';
  if (close < previousClose) return 'var(--ts-price-down-text)';
  return 'var(--ts-status-line-value-text)';
}

function formatValueOrDash(value: number | null, formatter: (v: number) => string): string {
  return value != null ? formatter(value) : '--';
}

/* ----- Component --------------------------------------------------------- */

interface OhlcvFieldProps {
  label: string;
  value: string;
  style?: CSSProperties;
}

function OhlcvField({ label, value, style }: OhlcvFieldProps): React.JSX.Element {
  return (
    <span style={{ display: 'inline-flex', alignItems: 'center', gap: '2px' }}>
      <span style={labelStyle}>{label}</span>
      <span className="ts-data-value" style={style ?? valueStyle}>{value}</span>
    </span>
  );
}

export function StatusLine({
  open,
  high,
  low,
  close,
  volume,
  previousClose,
  precision = 2,
  symbol,
  stale = false,
}: StatusLineProps): React.JSX.Element {
  const closeColor = getCloseColor(close, previousClose);

  return (
    <div style={containerStyle} data-testid="status-line" role="status">
      {symbol !== undefined && (
        <span style={symbolStyle} data-testid="status-line-symbol">{symbol}</span>
      )}
      <OhlcvField label="O" value={formatValueOrDash(open, (v) => formatPrice(v, precision))} />
      <OhlcvField label="H" value={formatValueOrDash(high, (v) => formatPrice(v, precision))} />
      <OhlcvField label="L" value={formatValueOrDash(low, (v) => formatPrice(v, precision))} />
      <OhlcvField
        label="C"
        value={formatValueOrDash(close, (v) => formatPrice(v, precision))}
        style={{ ...valueStyle, color: closeColor }}
      />
      <OhlcvField label="Vol" value={formatValueOrDash(volume, formatCompactNumber)} />
      {stale && (
        <span style={staleTagStyle} data-testid="status-line-stale" aria-label="Data is stale">
          (stale)
        </span>
      )}
    </div>
  );
}

StatusLine.displayName = 'StatusLine';
