import { useCallback, useState, type CSSProperties } from 'react';
import { DropdownMenu, Button, Input, IconButton } from '../../primitives';
import { ChevronDown, Trash2, Save } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  AlertTemplateManager                                                      */
/*  Dropdown for saving, loading, and deleting alert templates.               */
/*  Composes Phase 0 DropdownMenu, Button, Input, IconButton.                 */
/*  Uses --ts-menu-*, --ts-overlay-* tokens.                                  */
/* -------------------------------------------------------------------------- */

export interface AlertTemplateManagerProps {
  /** Available templates. */
  templates: Array<{ id: string; name: string }>;
  /** Called when a template is loaded. */
  onTemplateLoad: (templateId: string) => void;
  /** Called when the current configuration is saved as a new template. */
  onTemplateSave: (name: string) => void;
  /** Called when a template is deleted. */
  onTemplateDelete: (templateId: string) => void;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-alert-template-manager-styles';

function ensureAlertTemplateManagerStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-alert-template-item]:hover [data-ts-template-delete] {
      opacity: 1;
    }
    [data-ts-template-delete] {
      opacity: 0;
      transition: opacity 150ms;
    }
    [data-ts-template-delete]:focus-visible {
      opacity: 1;
      outline: 2px solid var(--ts-accent-default);
      outline-offset: 1px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureAlertTemplateManagerStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const saveRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
  padding: 'var(--ts-space-2) var(--ts-space-3)',
};

const templateItemStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'space-between',
  width: '100%',
};

const templateNameStyle: CSSProperties = {
  flex: 1,
  minWidth: 0,
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  whiteSpace: 'nowrap',
  fontSize: 'var(--ts-font-sm)',
  fontFamily: 'inherit',
};

const emptyStyle: CSSProperties = {
  padding: 'var(--ts-space-3) var(--ts-space-4)',
  fontSize: 'var(--ts-font-sm)',
  color: 'var(--ts-text-tertiary)',
  fontFamily: 'inherit',
  textAlign: 'center',
};

/* ----- Component --------------------------------------------------------- */

export function AlertTemplateManager({
  templates,
  onTemplateLoad,
  onTemplateSave,
  onTemplateDelete,
}: AlertTemplateManagerProps): React.JSX.Element {
  const [saving, setSaving] = useState(false);
  const [saveName, setSaveName] = useState('');

  const handleSaveSubmit = useCallback(() => {
    const trimmed = saveName.trim();
    if (trimmed) {
      onTemplateSave(trimmed);
      setSaveName('');
      setSaving(false);
    }
  }, [saveName, onTemplateSave]);

  const handleSaveKeyDown = useCallback(
    (e: React.KeyboardEvent) => {
      if (e.key === 'Enter') {
        e.preventDefault();
        handleSaveSubmit();
      }
      if (e.key === 'Escape') {
        setSaving(false);
        setSaveName('');
      }
    },
    [handleSaveSubmit],
  );

  return (
    <div data-ts-alert-template-manager="">
      <DropdownMenu.Root>
        <DropdownMenu.Trigger>
          <Button variant="ghost" size="sm" data-testid="templates-trigger">
            Templates
            <ChevronDown size={14} style={{ marginLeft: 'var(--ts-space-1)' }} />
          </Button>
        </DropdownMenu.Trigger>
        <DropdownMenu.Content>
          {/* Save current as... */}
          {saving ? (
            <div style={saveRowStyle} data-testid="save-input-row">
              <Input
                value={saveName}
                onChange={(e) => setSaveName(e.target.value)}
                onKeyDown={handleSaveKeyDown}
                placeholder="Template name..."
                size="sm"
                autoFocus
                data-testid="template-name-input"
              />
              <IconButton
                icon={<Save size={14} />}
                label="Save template"
                size="sm"
                variant="ghost"
                onClick={handleSaveSubmit}
                disabled={!saveName.trim()}
              />
            </div>
          ) : (
            <DropdownMenu.Item onSelect={() => setSaving(true)} data-testid="save-current-option">
              Save current as...
            </DropdownMenu.Item>
          )}

          {templates.length > 0 ? (
            <>
              <DropdownMenu.Separator />
              {templates.map((template) => (
                <DropdownMenu.Item
                  key={template.id}
                  onSelect={() => onTemplateLoad(template.id)}
                  data-ts-alert-template-item=""
                  data-testid={`template-${template.id}`}
                >
                  <span style={templateItemStyle}>
                    <span style={templateNameStyle}>{template.name}</span>
                    <button
                      type="button"
                      data-ts-template-delete=""
                      style={{
                        all: 'unset',
                        display: 'inline-flex',
                        alignItems: 'center',
                        cursor: 'pointer',
                        color: 'var(--ts-text-tertiary)',
                        padding: '2px',
                        borderRadius: 'var(--ts-radius-sm)',
                      }}
                      onClick={(e) => {
                        e.stopPropagation();
                        onTemplateDelete(template.id);
                      }}
                      aria-label={`Delete template ${template.name}`}
                    >
                      <Trash2 size={12} />
                    </button>
                  </span>
                </DropdownMenu.Item>
              ))}
            </>
          ) : (
            <div style={emptyStyle} data-testid="no-templates">
              No saved templates
            </div>
          )}
        </DropdownMenu.Content>
      </DropdownMenu.Root>
    </div>
  );
}

AlertTemplateManager.displayName = 'AlertTemplateManager';
