import { useCallback, useMemo, useState, type CSSProperties } from 'react';
import { Input, Select, Button, IconButton } from '../../primitives';
import { Plus, X } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  WebhookConfig                                                             */
/*  Webhook URL, method, headers, and payload template configuration.         */
/*  Supports URL validation, dynamic header rows, and template preview.       */
/*  Uses --ts-input-*, --ts-border-* tokens.                                  */
/* -------------------------------------------------------------------------- */

export interface WebhookConfigProps {
  /** Webhook URL. */
  url: string;
  /** Called when URL changes. */
  onUrlChange: (url: string) => void;
  /** HTTP method. */
  method: 'GET' | 'POST' | 'PUT';
  /** Called when method changes. */
  onMethodChange: (method: 'GET' | 'POST' | 'PUT') => void;
  /** Custom headers as key-value pairs. */
  headers: Array<{ key: string; value: string }>;
  /** Called when headers change. */
  onHeadersChange: (headers: Array<{ key: string; value: string }>) => void;
  /** Payload template string with {{placeholder}} support. */
  payloadTemplate: string;
  /** Called when payload template changes. */
  onPayloadTemplateChange: (template: string) => void;
  /** Whether to show the payload preview. */
  showPreview?: boolean;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-webhook-config-styles';

function ensureWebhookConfigStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-webhook-config] textarea:focus {
      border-color: var(--ts-input-border-focus);
      outline: 1px solid var(--ts-input-border-focus);
      outline-offset: -1px;
    }
    [data-ts-webhook-config] textarea:hover {
      border-color: var(--ts-input-border-hover);
    }
    [data-ts-webhook-url-status="valid"] {
      color: var(--ts-status-success);
    }
    [data-ts-webhook-url-status="invalid"] {
      color: var(--ts-status-error);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureWebhookConfigStyles();
}

/* ----- Styles ------------------------------------------------------------ */

const containerStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: 'var(--ts-space-3)',
};

const rowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
};

const labelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-sm)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  color: 'var(--ts-text-secondary)',
  fontFamily: 'inherit',
  marginBottom: 'var(--ts-space-1)',
};

const methodSelectStyle: CSSProperties = {
  width: 100,
  flexShrink: 0,
};

const urlInputStyle: CSSProperties = {
  flex: 1,
  minWidth: 0,
};

const validationStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  fontFamily: 'inherit',
  marginTop: 'calc(-1 * var(--ts-space-2))',
};

const headerRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-2)',
};

const headerKeyStyle: CSSProperties = {
  flex: 1,
  minWidth: 0,
};

const headerValueStyle: CSSProperties = {
  flex: 2,
  minWidth: 0,
};

const textareaStyle: CSSProperties = {
  width: '100%',
  minHeight: 80,
  padding: 'var(--ts-space-2)',
  background: 'var(--ts-input-bg)',
  color: 'var(--ts-input-text)',
  border: '1px solid var(--ts-input-border)',
  borderRadius: 'var(--ts-input-radius)',
  fontSize: 'var(--ts-font-sm)',
  fontFamily: 'monospace',
  resize: 'vertical',
  boxSizing: 'border-box',
  transition: 'border-color 150ms',
};

const previewStyle: CSSProperties = {
  padding: 'var(--ts-space-2) var(--ts-space-3)',
  background: 'oklch(0.50 0.005 260 / 0.04)',
  borderRadius: 'var(--ts-radius-sm)',
  fontSize: 'var(--ts-font-xs)',
  fontFamily: 'monospace',
  color: 'var(--ts-text-secondary)',
  whiteSpace: 'pre-wrap',
  wordBreak: 'break-all',
  lineHeight: 1.5,
};

const placeholderHintStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
  fontFamily: 'inherit',
  lineHeight: 1.4,
};

/* ----- Helpers ----------------------------------------------------------- */

function isValidUrl(url: string): boolean {
  if (!url) return false;
  try {
    new URL(url);
    return true;
  } catch {
    return false;
  }
}

const SAMPLE_VALUES: Record<string, string> = {
  ticker: 'BTCUSDT',
  price: '70,123.45',
  close: '70,100.00',
  exchange: 'Binance',
  timestamp: '2026-03-12T10:30:00Z',
};

function resolveTemplate(template: string): string {
  return template.replace(/\{\{(\w+)\}\}/g, (_, key: string) => SAMPLE_VALUES[key] ?? `{{${key}}}`);
}

/* ----- Component --------------------------------------------------------- */

export function WebhookConfig({
  url,
  onUrlChange,
  method,
  onMethodChange,
  headers,
  onHeadersChange,
  payloadTemplate,
  onPayloadTemplateChange,
  showPreview = false,
}: WebhookConfigProps): React.JSX.Element {
  const [urlTouched, setUrlTouched] = useState(false);

  const methodOptions = [
    { value: 'GET', label: 'GET' },
    { value: 'POST', label: 'POST' },
    { value: 'PUT', label: 'PUT' },
  ];

  const urlValid = isValidUrl(url);
  const showUrlValidation = urlTouched && url.length > 0;

  const handleAddHeader = useCallback(() => {
    onHeadersChange([...headers, { key: '', value: '' }]);
  }, [headers, onHeadersChange]);

  const handleRemoveHeader = useCallback(
    (index: number) => {
      onHeadersChange(headers.filter((_, i) => i !== index));
    },
    [headers, onHeadersChange],
  );

  const handleHeaderChange = useCallback(
    (index: number, field: 'key' | 'value', val: string) => {
      const updated = headers.map((h, i) =>
        i === index ? { ...h, [field]: val } : h,
      );
      onHeadersChange(updated);
    },
    [headers, onHeadersChange],
  );

  const showPayloadSection = method !== 'GET';
  const resolvedPreview = useMemo(() => resolveTemplate(payloadTemplate), [payloadTemplate]);

  return (
    <div data-ts-webhook-config="" style={containerStyle}>
      {/* URL + Method */}
      <div>
        <span style={labelStyle}>Webhook URL</span>
        <div style={rowStyle}>
          <div style={methodSelectStyle}>
            <Select
              options={methodOptions}
              value={method}
              onValueChange={(v) => onMethodChange(v as 'GET' | 'POST' | 'PUT')}
              size="sm"
              label="HTTP method"
            />
          </div>
          <div style={urlInputStyle}>
            <Input
              value={url}
              onChange={(e) => onUrlChange(e.target.value)}
              onBlur={() => setUrlTouched(true)}
              placeholder="https://example.com/webhook"
              size="sm"
              error={showUrlValidation && !urlValid}
              data-testid="webhook-url-input"
            />
          </div>
        </div>
        {showUrlValidation ? (
          <span
            style={validationStyle}
            data-ts-webhook-url-status={urlValid ? 'valid' : 'invalid'}
            data-testid="url-validation"
          >
            {urlValid ? 'Valid URL' : 'Invalid URL format'}
          </span>
        ) : null}
      </div>

      {/* Headers */}
      <div>
        <span style={labelStyle}>Headers</span>
        {headers.map((header, i) => (
          <div key={i} style={{ ...headerRowStyle, marginBottom: 'var(--ts-space-1)' }}>
            <div style={headerKeyStyle}>
              <Input
                value={header.key}
                onChange={(e) => handleHeaderChange(i, 'key', e.target.value)}
                placeholder="Header name"
                size="sm"
                data-testid={`header-key-${i}`}
              />
            </div>
            <div style={headerValueStyle}>
              <Input
                value={header.value}
                onChange={(e) => handleHeaderChange(i, 'value', e.target.value)}
                placeholder="Header value"
                size="sm"
                data-testid={`header-value-${i}`}
              />
            </div>
            <IconButton
              icon={<X size={14} />}
              label={`Remove header ${i + 1}`}
              size="sm"
              variant="ghost"
              onClick={() => handleRemoveHeader(i)}
            />
          </div>
        ))}
        <Button
          variant="ghost"
          size="sm"
          onClick={handleAddHeader}
          data-testid="add-header"
        >
          <Plus size={14} style={{ marginRight: 'var(--ts-space-1)' }} />
          Add header
        </Button>
      </div>

      {/* Payload Template */}
      {showPayloadSection ? (
        <div>
          <span style={labelStyle}>Payload template</span>
          <textarea
            style={textareaStyle}
            value={payloadTemplate}
            onChange={(e) => onPayloadTemplateChange(e.target.value)}
            placeholder='{"ticker": "{{ticker}}", "price": "{{price}}"}'
            data-testid="payload-template"
          />
          <span style={placeholderHintStyle}>
            {'Available placeholders: {{ticker}}, {{price}}, {{close}}, {{exchange}}, {{timestamp}}'}
          </span>
        </div>
      ) : null}

      {/* Payload Preview */}
      {showPreview && showPayloadSection && payloadTemplate ? (
        <div>
          <span style={labelStyle}>Preview</span>
          <div style={previewStyle} data-testid="payload-preview">
            {resolvedPreview}
          </div>
        </div>
      ) : null}
    </div>
  );
}

WebhookConfig.displayName = 'WebhookConfig';
