/**
 * Pill-shaped symbol chip used as a drag handle for cross-app drag-drop.
 *
 * Shows the ticker text with exchange icon. When the user starts a mouse
 * drag on this element, it triggers the cross-app drag protocol via the
 * `onDragStart` callback. Also serves as the drag ghost reference.
 */

import { forwardRef, useCallback, type KeyboardEventHandler, type MouseEventHandler } from "react";

export interface DraggableSymbolChipProps {
  /** Symbol ticker (e.g., "BTCUSDT"). */
  symbol: string;
  /** Exchange name (e.g., "binance"). */
  exchange?: string;
  /** Called on mousedown to initiate cross-app drag tracking. */
  onDragStart?: (event: React.MouseEvent) => void;
  /** Called on double-click (typically opens chart). */
  onDoubleClick?: MouseEventHandler;
}

function ensureDraggableSymbolChipStyles() {
  if (typeof document === "undefined") return;
  const id = "ts-draggable-symbol-chip-styles";
  if (document.getElementById(id)) return;
  const style = document.createElement("style");
  style.id = id;
  style.textContent = `
    [data-ts-symbol-chip] {
      display: inline-flex;
      align-items: center;
      gap: 4px;
      padding: 2px 8px;
      border-radius: var(--ts-radius-sm, 4px);
      font-family: var(--ts-font-data, monospace);
      font-size: 12px;
      font-weight: var(--ts-font-weight-bold, 460);
      font-variant-numeric: tabular-nums;
      color: var(--ts-watchlist-symbol-text, #e0e0e0);
      cursor: grab;
      user-select: none;
      white-space: nowrap;
      transition: background 0.12s;
    }
    [data-ts-symbol-chip]:hover {
      background: var(--ts-surface-hover, rgba(255,255,255,0.06));
    }
    [data-ts-symbol-chip]:active {
      cursor: grabbing;
    }
    [data-ts-symbol-chip]:focus-visible {
      outline: 2px solid var(--ts-accent-default, #3b82f6);
      outline-offset: 1px;
    }
    [data-ts-symbol-chip] .ts-chip-exchange {
      font-size: 10px;
      font-weight: 400;
      color: var(--ts-text-muted, #888);
      text-transform: lowercase;
    }
  `;
  document.head.appendChild(style);
}

export const DraggableSymbolChip = forwardRef<HTMLDivElement, DraggableSymbolChipProps>(
  function DraggableSymbolChip({ symbol, exchange, onDragStart, onDoubleClick }, ref) {
    ensureDraggableSymbolChipStyles();

    const handleMouseDown = useCallback(
      (e: React.MouseEvent) => {
        // Only left button
        if (e.button !== 0) return;
        onDragStart?.(e);
      },
      [onDragStart],
    );

    // Keyboard alternative to drag: Enter/Space activates the primary action (open chart).
    const handleKeyDown: KeyboardEventHandler = useCallback(
      (e) => {
        if (e.key === "Enter" || e.key === " ") {
          e.preventDefault();
          onDoubleClick?.(e as unknown as React.MouseEvent<HTMLDivElement>);
        }
      },
      [onDoubleClick],
    );

    return (
      <div
        ref={ref}
        data-ts-symbol-chip
        onMouseDown={handleMouseDown}
        onDoubleClick={onDoubleClick}
        onKeyDown={handleKeyDown}
        role="button"
        tabIndex={0}
        aria-label={`Drag ${symbol}${exchange ? ` from ${exchange}` : ""} to another app, or press Enter to open`}
        aria-roledescription="draggable symbol"
      >
        <span>{symbol}</span>
        {exchange && <span className="ts-chip-exchange">{exchange}</span>}
      </div>
    );
  },
);

DraggableSymbolChip.displayName = "DraggableSymbolChip";
