/**
 * FDC3 channel bridge for feed status data.
 *
 * Manages a SINGLE FDC3 channel subscription to `deskmodal.status`
 * on behalf of all apps that need exchange connection health info.
 */

/* -------------------------------------------------------------------------- */
/*  Structured logging                                                         */
/* -------------------------------------------------------------------------- */

function structuredLog(level: 'error' | 'warn' | 'info', message: string): void {
  if (typeof window === 'undefined') return;
  const win = window as { deskmodal?: { log?: (level: string, msg: string) => void } };
  if (win.deskmodal?.log) {
    win.deskmodal.log(level, message);
  }
}

/* -------------------------------------------------------------------------- */
/*  FDC3 types (minimal, to avoid circular dep on @deskmodal/fdc3)          */
/* -------------------------------------------------------------------------- */

interface FDC3Context {
  type: string;
  [key: string]: unknown;
}

interface FDC3Listener {
  unsubscribe(): void;
}

interface FDC3Channel {
  addContextListener(
    contextType: string | null,
    handler: (context: FDC3Context) => void,
  ): Promise<FDC3Listener>;
}

interface FDC3Agent {
  getOrCreateChannel(id: string): Promise<FDC3Channel>;
}

/* -------------------------------------------------------------------------- */
/*  FeedStatus types                                                           */
/* -------------------------------------------------------------------------- */

/** Status of a single exchange from the price-feed service. */
export interface FeedStatusExchange {
  readonly exchangeId: string;
  readonly connected: boolean;
  readonly tickCount: number;
  readonly errorCount: number;
  readonly lastTickTime?: number;
  readonly uptimeStart?: number;
  readonly circuitBreakerState: string;
  readonly subscribedCount?: number;
}

/** Aggregate feed status across all exchanges. */
export interface FeedStatus {
  readonly exchanges: FeedStatusExchange[];
}

/* -------------------------------------------------------------------------- */
/*  Internal state                                                             */
/* -------------------------------------------------------------------------- */

const STATUS_CHANNEL = 'deskmodal.status';

let statusInitialized = false;
const statusListeners: FDC3Listener[] = [];

type StatusCallback = (status: FeedStatus) => void;
const statusCallbacks = new Set<StatusCallback>();

/** Latest status snapshot. */
let latestStatus: FeedStatus | null = null;

/* -------------------------------------------------------------------------- */
/*  Context parsing                                                            */
/* -------------------------------------------------------------------------- */

function contextToFeedStatus(context: FDC3Context): FeedStatus | null {
  if (context.type !== 'deskmodal.feedStatus') return null;

  // The price-feed service wraps status in a nested `status` field,
  // while intent results may put exchanges at the top level.
  const raw = context as unknown as Record<string, unknown>;
  const nested = raw['status'] as Record<string, unknown> | undefined;
  const statusData: FeedStatus | null =
    nested && Array.isArray(nested['exchanges'])
      ? (nested as unknown as FeedStatus)
      : Array.isArray(raw['exchanges'])
        ? (raw as unknown as FeedStatus)
        : null;

  if (!statusData?.exchanges) return null;
  return statusData;
}

/* -------------------------------------------------------------------------- */
/*  Bridge setup                                                               */
/* -------------------------------------------------------------------------- */

async function setupStatusListener(agent: FDC3Agent): Promise<void> {
  const channel = await agent.getOrCreateChannel(STATUS_CHANNEL);
  const listener = await channel.addContextListener(
    'deskmodal.feedStatus',
    (context: FDC3Context) => {
      const status = contextToFeedStatus(context);
      if (!status) return;

      latestStatus = status;

      for (const cb of statusCallbacks) {
        try {
          cb(status);
        } catch (err) {
          structuredLog('error', `[status-bridge] Status callback error: ${String(err)}`);
        }
      }
    },
  );

  statusListeners.push(listener);
}

function initWithRetry(agent: FDC3Agent): void {
  const maxRetries = 5;
  let retryCount = 0;

  function attempt(): void {
    setupStatusListener(agent).catch((err) => {
      retryCount += 1;
      structuredLog(
        'error',
        `[status-bridge] Status channel setup failed (attempt ${retryCount}/${maxRetries}): ${String(err)}`,
      );
      if (retryCount < maxRetries) {
        const delayMs = Math.min(1000 * Math.pow(2, retryCount), 30_000);
        window.setTimeout(attempt, delayMs);
      } else {
        structuredLog('error', '[status-bridge] Status channel setup failed after max retries');
        statusInitialized = false;
      }
    });
  }

  attempt();
}

function detectAndInit(): void {
  if (typeof window === 'undefined') return;

  const win = window as { fdc3?: FDC3Agent };

  if (win.fdc3) {
    initWithRetry(win.fdc3);
    return;
  }

  function onFdc3Ready(): void {
    window.removeEventListener('fdc3Ready', onFdc3Ready);
    if (win.fdc3) {
      initWithRetry(win.fdc3);
    }
  }

  window.addEventListener('fdc3Ready', onFdc3Ready);
}

/* -------------------------------------------------------------------------- */
/*  Public API                                                                 */
/* -------------------------------------------------------------------------- */

/**
 * Initialize the FDC3 status bridge. Idempotent.
 *
 * Sets up a single FDC3 channel listener for `deskmodal.status` and
 * forwards parsed feed status updates to registered callbacks.
 */
export function initStatusBridge(): void {
  if (statusInitialized) return;
  statusInitialized = true;
  detectAndInit();
}

/**
 * Subscribe to feed status updates. Returns an unsubscribe function.
 */
export function onStatusUpdate(callback: StatusCallback): () => void {
  statusCallbacks.add(callback);
  return () => {
    statusCallbacks.delete(callback);
  };
}

/** Get the most recently received feed status, or null if none yet. */
export function getLatestStatus(): FeedStatus | null {
  return latestStatus;
}

/**
 * Reset bridge state. Primarily for testing.
 */
export function resetStatusBridge(): void {
  statusInitialized = false;
  latestStatus = null;
  statusCallbacks.clear();
  for (const listener of statusListeners) {
    try {
      listener.unsubscribe();
    } catch {
      // Ignore cleanup errors
    }
  }
  statusListeners.length = 0;
}
