import { useState, useCallback, type CSSProperties } from 'react';
import { Dialog, NumberInput, Select, Button } from '../primitives';

/* -------------------------------------------------------------------------- */
/*  TimeframeCustomDialog                                                     */
/*  Modal dialog for entering a custom timeframe interval.                    */
/*  Uses Dialog primitive with --ts-dialog-* tokens.                          */
/* -------------------------------------------------------------------------- */

export type TimeframeUnit = 'ticks' | 'seconds' | 'minutes' | 'hours' | 'days' | 'weeks' | 'months';

export interface TimeframeCustomDialogProps {
  /** Whether the dialog is open. */
  open: boolean;
  /** Called when the open state changes. */
  onOpenChange: (open: boolean) => void;
  /** Called when a custom timeframe is submitted. */
  onSubmit: (value: number, unit: TimeframeUnit) => void;
}

/* ----- Style injection --------------------------------------------------- */

const STYLE_ID = 'ts-timeframe-custom-dialog-styles';

function ensureTimeframeCustomDialogStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = STYLE_ID;
  sheet.textContent = `
    [data-ts-timeframe-custom-dialog] [data-ts-timeframe-custom-dialog-body] {
      display: flex;
      flex-direction: column;
      gap: 16px;
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureTimeframeCustomDialogStyles();
}

/* ----- Constants --------------------------------------------------------- */

const UNIT_OPTIONS: { value: TimeframeUnit; label: string }[] = [
  { value: 'ticks', label: 'Ticks' },
  { value: 'seconds', label: 'Seconds' },
  { value: 'minutes', label: 'Minutes' },
  { value: 'hours', label: 'Hours' },
  { value: 'days', label: 'Days' },
  { value: 'weeks', label: 'Weeks' },
  { value: 'months', label: 'Months' },
];

/* ----- Styles ------------------------------------------------------------ */

const bodyStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: '16px',
  marginTop: '16px',
};

const fieldRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'flex-end',
  gap: '12px',
};

const fieldStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: '6px',
  flex: 1,
};

const labelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-sm)',
  color: 'var(--ts-text-secondary)',
  fontFamily: 'inherit',
};

const footerStyle: CSSProperties = {
  display: 'flex',
  justifyContent: 'flex-end',
  gap: 'var(--ts-dialog-footer-gap)',
  marginTop: '20px',
};

/* ----- Component --------------------------------------------------------- */

export function TimeframeCustomDialog({
  open,
  onOpenChange,
  onSubmit,
}: TimeframeCustomDialogProps): React.JSX.Element {
  const [multiplier, setMultiplier] = useState<number>(1);
  const [unit, setUnit] = useState<TimeframeUnit>('minutes');

  const handleApply = useCallback(() => {
    if (multiplier <= 0) return;
    onSubmit(multiplier, unit);
    onOpenChange(false);
  }, [multiplier, unit, onSubmit, onOpenChange]);

  const handleCancel = useCallback(() => {
    onOpenChange(false);
  }, [onOpenChange]);

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <Dialog.Content data-ts-timeframe-custom-dialog="" style={{ maxWidth: 320 }}>
        <Dialog.Title>Custom Interval</Dialog.Title>
        <div style={bodyStyle} data-ts-timeframe-custom-dialog-body="">
          <div style={fieldRowStyle}>
            <div style={fieldStyle}>
              <span style={labelStyle}>Value</span>
              <NumberInput
                value={multiplier}
                onChange={setMultiplier}
                min={1}
                max={999}
                step={1}
                size="md"
                label="Interval value"
              />
            </div>
            <div style={fieldStyle}>
              <span style={labelStyle}>Unit</span>
              <Select
                options={UNIT_OPTIONS}
                value={unit}
                onValueChange={(v) => setUnit(v as TimeframeUnit)}
                size="md"
                label="Interval unit"
              />
            </div>
          </div>
        </div>
        <div style={footerStyle}>
          <Dialog.Close>
            <Button variant="secondary" onClick={handleCancel}>
              Cancel
            </Button>
          </Dialog.Close>
          <Button variant="primary" onClick={handleApply} disabled={multiplier <= 0}>
            Apply
          </Button>
        </div>
      </Dialog.Content>
    </Dialog>
  );
}

TimeframeCustomDialog.displayName = 'TimeframeCustomDialog';
