import { useState, useEffect, useCallback, useMemo, useRef } from 'react';
import type { ExchangeConnectionStatus } from '@deskmodal/ui-components';
import type { ExchangeId } from '@deskmodal/data-layer';
import { getFeedManager } from '../services/feed-service';
import { onStatusUpdate } from '../services/feed-service';
import { priceFeedClient } from '../services/price-feed-client';
import type { FeedStatus, FeedStatusExchange } from '../services/price-feed-client';
import type { FeedManager, ManagedExchange } from '../services/feed-manager';
import { toServiceError } from './use-service-health';
import type { ServiceError } from './use-service-health';

/* -------------------------------------------------------------------------- */
/*  useExchangeConnections                                                     */
/*  Event-driven hook — listens on the FDC3 status channel for updates.        */
/*  No polling. Does an initial getStatus() intent on mount.                   */
/* -------------------------------------------------------------------------- */

/** Detail view of an exchange connection. */
export interface ExchangeDetail {
  id: string;
  name: string;
  status: 'connected' | 'disconnected' | 'degraded' | 'connecting';
  websocketUrl: string;
  subscribedPairs: string[];
  latencyMs: number | null;
  messagesPerSecond: number;
  lastError: string | null;
  uptimePercent: number;
  reconnectCount: number;
  circuitBreakerState: 'closed' | 'open' | 'half-open';
}

/** Aggregate stats for the feeds dashboard. */
export interface FeedStats {
  connectedExchanges: number;
  totalExchanges: number;
  activeSymbols: number;
  totalMessagesPerSecond: number;
}

/** Price-feed service availability state. */
export type ServiceState = 'connecting' | 'ready' | 'unavailable' | 'degraded';

/** Result of a connect/disconnect operation. */
export interface ConnectionOperationResult {
  readonly success: boolean;
  readonly error?: string;
  readonly serviceError?: ServiceError;
}

/** Return type for the useExchangeConnections hook. */
export interface ExchangeConnectionsState {
  /** Connection statuses for the status bar. */
  connections: ExchangeConnectionStatus[];
  /** Dashboard-level stats. */
  stats: FeedStats;
  /** Detailed exchange information for the exchange list. */
  exchangeDetails: ExchangeDetail[];
  /** Connect to an exchange. Returns operation result. */
  connectExchange: (exchangeId: ExchangeId) => Promise<ConnectionOperationResult>;
  /** Disconnect from an exchange. Returns operation result. */
  disconnectExchange: (exchangeId: ExchangeId) => Promise<ConnectionOperationResult>;
  /** The FeedManager instance for sharing with other hooks. */
  manager: FeedManager;
  /** Whether the initial status fetch is in progress. */
  isLoading: boolean;
  /** Price-feed service availability state. */
  serviceState: ServiceState;
  /** Error message from the last failed operation, if any. */
  lastError: string | null;
  /** Structured error from the last failed operation, if any. */
  lastServiceError: ServiceError | null;
  /** Retry the service discovery probe. Re-attempts the initial getStatus() call. */
  retryServiceProbe: () => void;
}

/**
 * Build a ConnectionStatusBar-compatible status object from a ManagedExchange
 * and optional service status data.
 */
function buildConnectionStatus(
  managed: ManagedExchange,
  serviceStatus?: FeedStatusExchange,
  msgPerSec?: number,
): ExchangeConnectionStatus {
  const isConnected = serviceStatus?.connected ?? managed.connected;
  return {
    id: managed.exchangeId,
    name: managed.displayName,
    status: isConnected ? 'connected' : 'disconnected',
    pairsSubscribed: serviceStatus?.subscribedCount ?? 0,
    messagesPerSecond: msgPerSec ?? 0,
  };
}

/**
 * Compute messages per second from tick count deltas.
 */
function computeMsgPerSec(
  prevRef: Map<string, { count: number; time: number }>,
  exchangeId: string,
  currentTickCount: number,
): number {
  const now = Date.now();
  const prev = prevRef.get(exchangeId);
  if (prev && now - prev.time > 0) {
    const rate = ((currentTickCount - prev.count) / (now - prev.time)) * 1000;
    prevRef.set(exchangeId, { count: currentTickCount, time: now });
    return Math.round(rate * 10) / 10;
  }
  prevRef.set(exchangeId, { count: currentTickCount, time: now });
  return 0;
}

/**
 * Build an ExchangeDetail object from a ManagedExchange and service status.
 */
function buildExchangeDetail(
  managed: ManagedExchange,
  serviceStatus?: FeedStatusExchange,
  msgPerSec?: number,
): ExchangeDetail {
  const isConnected = serviceStatus?.connected ?? managed.connected;
  const uptimeMs = serviceStatus?.uptimeStart
    ? Date.now() - serviceStatus.uptimeStart
    : 0;
  const uptimePercent = isConnected && uptimeMs > 0
    ? Math.min(100, parseFloat(((uptimeMs / (uptimeMs + 1000)) * 100).toFixed(2)))
    : 0;

  return {
    id: managed.exchangeId,
    name: managed.displayName,
    status: isConnected ? 'connected' : 'disconnected',
    websocketUrl: managed.websocketUrl,
    subscribedPairs: [],
    latencyMs: null,
    messagesPerSecond: msgPerSec ?? 0,
    lastError: serviceStatus && serviceStatus.errorCount > 0
      ? `Connection issue — ${serviceStatus.errorCount} error${serviceStatus.errorCount > 1 ? 's' : ''} since last reconnect`
      : null,
    uptimePercent,
    reconnectCount: 0,
    circuitBreakerState: (serviceStatus?.circuitBreakerState ?? 'closed') as 'closed' | 'open' | 'half-open',
  };
}

/** Structured log helper — routes to DeskModal logging if available. */
function structuredLog(level: 'error' | 'warn' | 'info', message: string): void {
  const win = window as { deskmodal?: { log?: (level: string, msg: string) => void } };
  if (win.deskmodal?.log) {
    win.deskmodal.log(level, message);
  }
}

/** Timeout (ms) after which a previously-ready service is considered degraded. */
const SERVICE_DEGRADED_TIMEOUT_MS = 15_000;

/**
 * Manages exchange connection state, driven by FDC3 status channel events.
 *
 * On mount, performs an initial getStatus() intent with retry to seed the state.
 * Then listens for ts.feedStatus contexts on the deskmodal.status channel
 * for real-time updates. No polling.
 *
 * Exposes `serviceState` to inform the UI of price-feed service availability:
 * - `connecting` — initial status fetch in progress
 * - `ready` — service responded successfully
 * - `unavailable` — all retry attempts failed, service not reachable
 * - `degraded` — was ready, but no status update received within timeout
 */
export function useExchangeConnections(): ExchangeConnectionsState {
  const manager = getFeedManager();
  const [serviceStatuses, setServiceStatuses] = useState<Map<string, FeedStatusExchange>>(new Map());
  const [isLoading, setIsLoading] = useState(true);
  const [serviceState, setServiceState] = useState<ServiceState>('connecting');
  const [lastError, setLastError] = useState<string | null>(null);
  const [lastServiceError, setLastServiceError] = useState<ServiceError | null>(null);
  const [retryCount, setRetryCount] = useState(0);
  const prevTickCounts = useRef<Map<string, { count: number; time: number }>>(new Map());
  const msgPerSecRef = useRef<Map<string, number>>(new Map());
  const lastStatusUpdateRef = useRef<number>(0);

  const applyStatus = useCallback((status: FeedStatus): void => {
    if (!status?.exchanges || !Array.isArray(status.exchanges)) return;
    lastStatusUpdateRef.current = Date.now();
    setServiceStatuses((prev) => {
      const next = new Map(prev);
      for (const ex of status.exchanges) {
        next.set(ex.exchangeId, ex);
        // Compute msg/s
        const rate = computeMsgPerSec(prevTickCounts.current, ex.exchangeId, ex.tickCount);
        msgPerSecRef.current.set(ex.exchangeId, rate);
      }
      return next;
    });
  }, []);

  // Initial status fetch via intent with retry (handled by priceFeedClient.getStatus)
  // Re-runs when retryCount changes (triggered by retryServiceProbe).
  useEffect(() => {
    let cancelled = false;

    // On retry (not initial mount), reset state to show loading indicator
    if (retryCount > 0) {
      setIsLoading(true);
      setServiceState('connecting');
    }

    priceFeedClient.getStatus().then((status) => {
      if (cancelled) return;
      if (status?.exchanges && Array.isArray(status.exchanges)) {
        applyStatus(status);
      }
      setServiceState('ready');
      setLastError(null);
      setLastServiceError(null);
    }).catch((err: unknown) => {
      if (cancelled) return;
      const svcError = toServiceError(err);
      structuredLog('error', `[use-exchange-connections] Service unavailable after retries: ${svcError.message}`);
      setServiceState('unavailable');
      setLastError(svcError.message);
      setLastServiceError(svcError);
    }).finally(() => {
      if (!cancelled) setIsLoading(false);
    });

    return () => {
      cancelled = true;
    };
  }, [applyStatus, retryCount]);

  // Listen for status updates from the FDC3 status channel
  useEffect(() => {
    const unsubscribe = onStatusUpdate((status: FeedStatus) => {
      applyStatus(status);
      // Any status update from the channel means the service is alive
      setServiceState('ready');
      setLastError(null);
      setLastServiceError(null);
    });

    return unsubscribe;
  }, [applyStatus]);

  // Degradation detection: if service was ready but no updates within timeout
  useEffect(() => {
    const intervalId = window.setInterval(() => {
      if (lastStatusUpdateRef.current === 0) return;
      const elapsed = Date.now() - lastStatusUpdateRef.current;
      if (elapsed > SERVICE_DEGRADED_TIMEOUT_MS) {
        setServiceState((prev) => {
          // Only degrade from ready state; don't overwrite unavailable
          if (prev === 'ready') {
            structuredLog('warn', `[use-exchange-connections] No status update for ${Math.round(elapsed / 1000)}s — marking degraded`);
            return 'degraded';
          }
          return prev;
        });
      }
    }, 2_000);

    return () => {
      window.clearInterval(intervalId);
    };
  }, []);

  const retryServiceProbe = useCallback(() => {
    setRetryCount((prev) => prev + 1);
  }, []);

  const connectExchange = useCallback(
    async (exchangeId: ExchangeId): Promise<ConnectionOperationResult> => {
      try {
        const result = await manager.connect(exchangeId);
        if (!result.success) {
          const errorMsg = result.error ?? `Failed to connect to ${exchangeId}`;
          const svcError: ServiceError = { code: 'rejected', message: errorMsg, retryable: false };
          structuredLog('error', `[use-exchange-connections] Connect failed: ${errorMsg}`);
          setLastError(errorMsg);
          setLastServiceError(svcError);
          return { success: false, error: errorMsg, serviceError: svcError };
        }
        return { success: true };
      } catch (err: unknown) {
        const svcError = toServiceError(err);
        structuredLog('error', `[use-exchange-connections] Connect error for ${exchangeId}: ${svcError.message}`);
        setLastError(svcError.message);
        setLastServiceError(svcError);
        return { success: false, error: svcError.message, serviceError: svcError };
      }
    },
    [manager],
  );

  const disconnectExchange = useCallback(
    async (exchangeId: ExchangeId): Promise<ConnectionOperationResult> => {
      try {
        const result = await manager.disconnect(exchangeId);
        if (!result.success) {
          const errorMsg = result.error ?? `Failed to disconnect from ${exchangeId}`;
          const svcError: ServiceError = { code: 'rejected', message: errorMsg, retryable: false };
          structuredLog('error', `[use-exchange-connections] Disconnect failed: ${errorMsg}`);
          setLastError(errorMsg);
          setLastServiceError(svcError);
          return { success: false, error: errorMsg, serviceError: svcError };
        }
        return { success: true };
      } catch (err: unknown) {
        const svcError = toServiceError(err);
        structuredLog('error', `[use-exchange-connections] Disconnect error for ${exchangeId}: ${svcError.message}`);
        setLastError(svcError.message);
        setLastServiceError(svcError);
        return { success: false, error: svcError.message, serviceError: svcError };
      }
    },
    [manager],
  );

  const connections = useMemo<ExchangeConnectionStatus[]>(() => {
    return manager.getExchanges().map((managed) => {
      const svcStatus = serviceStatuses.get(managed.exchangeId);
      const msgRate = msgPerSecRef.current.get(managed.exchangeId);
      return buildConnectionStatus(managed, svcStatus, msgRate);
    });
  }, [manager, serviceStatuses]);

  const exchangeDetails = useMemo<ExchangeDetail[]>(() => {
    return manager.getExchanges().map((managed) => {
      const svcStatus = serviceStatuses.get(managed.exchangeId);
      const msgRate = msgPerSecRef.current.get(managed.exchangeId);
      return buildExchangeDetail(managed, svcStatus, msgRate);
    });
  }, [manager, serviceStatuses]);

  const stats = useMemo<FeedStats>(() => {
    const connectedCount = connections.filter((c) => c.status === 'connected').length;
    const totalMsgPerSec = connections.reduce(
      (sum, c) => sum + (c.messagesPerSecond ?? 0),
      0,
    );
    const activePairs = connections.reduce(
      (sum, c) => sum + (c.pairsSubscribed ?? 0),
      0,
    );

    return {
      connectedExchanges: connectedCount,
      totalExchanges: connections.length,
      activeSymbols: activePairs,
      totalMessagesPerSecond: totalMsgPerSec,
    };
  }, [connections]);

  return {
    connections,
    stats,
    exchangeDetails,
    connectExchange,
    disconnectExchange,
    manager,
    isLoading,
    serviceState,
    lastError,
    lastServiceError,
    retryServiceProbe,
  };
}
