/* -------------------------------------------------------------------------- */
/*  Structured logging helper                                                  */
/* -------------------------------------------------------------------------- */

function structuredLog(level: 'error' | 'warn' | 'info', message: string): void {
  const win = window as { deskmodal?: { log?: (level: string, msg: string) => void } };
  if (win.deskmodal?.log) {
    win.deskmodal.log(level, message);
  }
}

/* -------------------------------------------------------------------------- */
/*  Error Boundary                                                             */
/* -------------------------------------------------------------------------- */

interface ErrorBoundaryState {
  hasError: boolean;
  error: Error | null;
}

class FeedsErrorBoundary extends Component<{ children: ReactNode }, ErrorBoundaryState> {
  state: ErrorBoundaryState = { hasError: false, error: null };

  static getDerivedStateFromError(error: Error): ErrorBoundaryState {
    return { hasError: true, error };
  }

  componentDidCatch(error: Error, info: React.ErrorInfo): void {
    structuredLog('error', `[FeedsErrorBoundary] ${error.message}\n${info.componentStack ?? ''}`);
  }

  handleRetry = (): void => {
    this.setState({ hasError: false, error: null });
  };

  render(): ReactNode {
    if (this.state.hasError) {
      return (
        <div
          data-ts-error-boundary=""
        >
          <span data-ts-error-title="">
            Something went wrong
          </span>
          <span data-ts-error-message="">
            {this.state.error?.message ?? 'An unexpected error occurred'}
          </span>
          <button
            data-ts-retry-button=""
            onClick={this.handleRetry}
          >
            Retry
          </button>
        </div>
      );
    }
    return this.props.children;
  }
}

/* -------------------------------------------------------------------------- */
/*  Service Health Banner                                                       */
/* -------------------------------------------------------------------------- */

/** Messages for each service state. */
const SERVICE_STATE_MESSAGES: Record<Exclude<ServiceState, 'ready'>, string> = {
  connecting: 'Connecting to price feed service...',
  unavailable: 'Price Feed Service unavailable. Check service status in DeskModal.',
  degraded: 'Price Feed Service not responding. Data may be stale.',
};

/** Map service state to CSS severity attribute. */
const SERVICE_STATE_SEVERITY: Record<Exclude<ServiceState, 'ready'>, string> = {
  connecting: 'restarting',
  unavailable: 'failed',
  degraded: 'degraded',
};

function ServiceHealthBanner({ serviceState }: { serviceState: ServiceState }): React.JSX.Element | null {
  if (serviceState === 'ready') return null;

  return (
    <div
      data-ts-service-banner=""
      data-ts-severity={SERVICE_STATE_SEVERITY[serviceState]}
      role="alert"
      aria-live="polite"
    >
      {SERVICE_STATE_MESSAGES[serviceState]}
    </div>
  );
}

/* -------------------------------------------------------------------------- */
/*  Latency history tracker                                                   */
/* -------------------------------------------------------------------------- */

const MAX_LATENCY_HISTORY = 30;

function useLatencyHistories(
  exchangeDetails: ReadonlyArray<{ id: string; latencyMs: number | null }>,
): Map<string, number[]> {
  const historyRef = useRef<Map<string, number[]>>(new Map());

  useEffect(() => {
    for (const exchange of exchangeDetails) {
      if (exchange.latencyMs === null) continue;
      const existing = historyRef.current.get(exchange.id) ?? [];
      const updated = [...existing, exchange.latencyMs].slice(-MAX_LATENCY_HISTORY);
      historyRef.current.set(exchange.id, updated);
    }
  });

  return historyRef.current;
}

/* -------------------------------------------------------------------------- */
/*  App                                                                       */
/* -------------------------------------------------------------------------- */

export function App(): React.JSX.Element {
  useStateResetNotification((msg) => toast.info({ title: msg, duration: 3000 }));

  const fdc3 = useFdc3();

  // Auto-join first user channel so FDC3 broadcasts work in modal windows
  useEffect(() => {
    if (!fdc3) return;
    fdc3.getUserChannels().then((channels) => {
      if (channels && channels.length > 0) {
        fdc3.joinUserChannel(channels[0]!.id).catch(() => {});
      }
    }).catch(() => {});
  }, [fdc3]);

  const [expanded, setExpanded] = useState(true);
  const [expandedExchangeId, setExpandedExchangeId] = useState<string | null>(null);
  const [addExchangeOpen, setAddExchangeOpen] = useState(false);
  const [wsFormOpen, setWsFormOpen] = useState(false);
  const [restFormOpen, setRestFormOpen] = useState(false);
  const [fileFormOpen, setFileFormOpen] = useState(false);

  // Session persistence for dock/undock state survival
  useSessionPersistence(
    'deskmodal:feeds:session',
    { expanded, expandedExchangeId },
    (saved) => {
      if (typeof saved.expanded === 'boolean') setExpanded(saved.expanded);
      if (saved.expandedExchangeId !== undefined) setExpandedExchangeId(saved.expandedExchangeId as string | null);
    },
    [expanded, expandedExchangeId],
  );

  const {
    connections,
    stats,
    exchangeDetails,
    connectExchange,
    disconnectExchange,
    isLoading,
    serviceState,
    lastError,
    retryServiceProbe,
  } = useExchangeConnections();

  const { addSource } = useCustomSources();
  const credentialsState = useExchangeCredentials();
  const livePrices = useLivePrices();
  const { recordTick, isSymbolStale: isSymbolStaleRaw } = useStaleData();
  const latencyHistories = useLatencyHistories(exchangeDetails);
  const { notify } = useDeskModalNotifications();

  // Record ticks for stale data detection whenever live prices update
  useEffect(() => {
    for (const [, prices] of livePrices) {
      for (const lp of prices) {
        recordTick(lp.exchangeId, lp.symbol);
      }
    }
  }, [livePrices, recordTick]);

  // Stale check callback for ExchangeRow
  const isSymbolStale = useCallback(
    (exchangeId: ExchangeId, symbol: string): boolean => {
      return isSymbolStaleRaw(symbol);
    },
    [isSymbolStaleRaw],
  );

  /* --- Toolbar widget integration --- */
  const connectionHealthSummary = `${stats.connectedExchanges}/${stats.totalExchanges} connected`;
  useToolbarWidgets(0, connectionHealthSummary);

  const handleToggle = useCallback(() => {
    setExpanded((prev) => !prev);
  }, []);

  const handleConnectExchange = useCallback(
    (exchangeId: ExchangeId) => {
      connectExchange(exchangeId).then((result) => {
        if (!result.success) {
          toast.error(result.error ?? `Failed to connect to ${exchangeId}`);
        }
      }).catch((err: unknown) => {
        toast.error(`Connection error: ${err instanceof Error ? err.message : String(err)}`);
      });
    },
    [connectExchange],
  );

  const handleDisconnectExchange = useCallback(
    (exchangeId: ExchangeId) => {
      disconnectExchange(exchangeId).then((result) => {
        if (!result.success) {
          toast.error(result.error ?? `Failed to disconnect from ${exchangeId}`);
        }
      }).catch((err: unknown) => {
        toast.error(`Disconnect error: ${err instanceof Error ? err.message : String(err)}`);
      });
    },
    [disconnectExchange],
  );

  const handleSaveCredentials = useCallback(
    (exchangeId: ExchangeId, credentials: ExchangeCredentials) => {
      credentialsState.saveCredentials(exchangeId, credentials).catch((err) => {
        toast.error(`Failed to save credentials for ${exchangeId}`);
        structuredLog('error', `[App] Credential save error: ${String(err)}`);
      });
    },
    [credentialsState],
  );

  const handleToggleExchangeRow = useCallback(
    (exchangeId: string) => {
      setExpandedExchangeId((prev) => (prev === exchangeId ? null : exchangeId));
    },
    [],
  );

  const connectedExchangeIds = useMemo(() => {
    const ids = new Set<string>();
    for (const detail of exchangeDetails) {
      if (detail.status === 'connected') {
        ids.add(detail.id);
      }
    }
    return ids;
  }, [exchangeDetails]);

  const handleEnableExchange = useCallback(
    (exchangeId: ExchangeId) => {
      connectExchange(exchangeId).then((result) => {
        if (!result.success) {
          toast.error(result.error ?? `Failed to enable ${exchangeId}`);
        }
      }).catch((err: unknown) => {
        toast.error(`Connection error: ${err instanceof Error ? err.message : String(err)}`);
      });
      setAddExchangeOpen(false);
    },
    [connectExchange],
  );

  const handleExchangeError = useCallback((message: string) => {
    toast.error(message);
  }, []);

  // Ctrl+K / Cmd+K — open Add Source browser (symbol search shortcut)
  useEffect(() => {
    function handleKeyDown(e: KeyboardEvent): void {
      if ((e.ctrlKey || e.metaKey) && e.key === 'k') {
        e.preventDefault();
        setAddExchangeOpen(true);
      }
    }
    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, []);

  return (
    <FeedsErrorBoundary>
    <AppShell
      header={
        <AppHeader
          title="Price Feed Hub"
          icon={<Radio size={16} />}
        />
      }
      footer={
        <ConnectionStatusBar
          connections={connections}
          totalMessagesPerSecond={stats.totalMessagesPerSecond}
          onExpandClick={handleToggle}
        />
      }
    >
      {serviceState !== 'ready' && serviceState !== 'unavailable' && (
        <ServiceHealthBanner serviceState={serviceState} />
      )}

      {serviceState === 'unavailable' ? (
        <ServiceUnavailableBanner
          onRetry={retryServiceProbe}
          error={lastError ?? undefined}
        />
      ) : expanded ? (
        <div data-ts-feeds-main="">
          {/* Compact stats strip */}
          <div data-ts-feeds-stats="">
            <div data-ts-feeds-stat="">
              <span data-ts-feeds-stat-value="">
                {stats.connectedExchanges}/{stats.totalExchanges}
              </span>
              <span data-ts-feeds-stat-label="">connected</span>
            </div>
            <span data-ts-feeds-stat-sep="" />
            <div data-ts-feeds-stat="">
              <span data-ts-feeds-stat-value="">{stats.activeSymbols}</span>
              <span data-ts-feeds-stat-label="">feeds</span>
            </div>
            <span data-ts-feeds-stat-sep="" />
            <div data-ts-feeds-stat="">
              <span data-ts-feeds-stat-value="">{stats.totalMessagesPerSecond}</span>
              <span data-ts-feeds-stat-label="">msg/s</span>
            </div>
          </div>

          {/* Exchange list — single scrollable view */}
          <div data-ts-exchange-list="">
            {isLoading ? (
              <div data-ts-skeleton="">
                {Array.from({ length: 4 }, (_, i) => (
                  <div key={i} data-ts-skeleton-row="" />
                ))}
              </div>
            ) : (
              exchangeDetails.map((exchange) => {
                const prices = livePrices.get(exchange.id as ExchangeId) ?? [];
                const latencyHistory = latencyHistories.get(exchange.id) ?? [];

                return (
                  <ExchangeRow
                    key={exchange.id}
                    exchange={exchange}
                    livePrices={prices}
                    latencyHistory={latencyHistory}
                    credentialStatus={credentialsState.getCredentialStatus(exchange.id as ExchangeId)}
                    expanded={expandedExchangeId === exchange.id}
                    onToggle={() => handleToggleExchangeRow(exchange.id)}
                    onConnect={handleConnectExchange}
                    onDisconnect={handleDisconnectExchange}
                    onSaveCredentials={handleSaveCredentials}
                    onError={handleExchangeError}
                    isSymbolStale={isSymbolStale}
                  />
                );
              })
            )}
          </div>

          {/* Add exchange button */}
          <div data-ts-feeds-actions="">
            <Button
              variant="ghost"
              size="sm"
              onClick={() => setAddExchangeOpen(true)}
            >
              <Plus size={14} />
              Add Source
            </Button>
          </div>
        </div>
      ) : (
        <DockPanel
          connections={connections}
          totalMessagesPerSecond={stats.totalMessagesPerSecond}
          vwapActive={false}
          expanded={expanded}
          onToggle={handleToggle}
          qualityDegraded={false}
        />
      )}

      {/* Dialogs */}
      <AddExchangeBrowser
        open={addExchangeOpen}
        onOpenChange={setAddExchangeOpen}
        connectedExchangeIds={connectedExchangeIds}
        onEnable={handleEnableExchange}
        onAddCustomWebSocket={() => setWsFormOpen(true)}
        onAddCustomRestApi={() => setRestFormOpen(true)}
        onAddFileImport={() => setFileFormOpen(true)}
      />

      <CustomWebSocketForm
        open={wsFormOpen}
        onOpenChange={setWsFormOpen}
        onSave={(source) => addSource(source)}
      />

      <CustomRestApiForm
        open={restFormOpen}
        onOpenChange={setRestFormOpen}
        onSave={(source) => addSource(source)}
      />

      <FileImportForm
        open={fileFormOpen}
        onOpenChange={setFileFormOpen}
        onSave={(source) => addSource(source)}
      />

      <Toaster position="bottom-right" theme="dark" />
    </AppShell>
    </FeedsErrorBoundary>
  );
}
