import { checkAppVersion } from '../../shared/version-gate';
checkAppVersion();

import { initTheme } from '@deskmodal/ui-components';
initTheme();

// Initialize FDC3 channel listeners for status and price updates.
// Does NOT start exchange connections — the native price-feed service handles those.
import { initFeedService } from './services/feed-service';
initFeedService();

import { createRoot } from 'react-dom/client';
import { App } from './App';

const container = document.getElementById('root');
if (!container) throw new Error('Root element not found');

createRoot(container).render(<App />);
