import { useState, useEffect, useRef, useCallback } from 'react';
import { onStatusUpdate } from '../services/feed-service';
import { priceFeedClient } from '../services/price-feed-client';
import type { FeedStatus } from '../services/price-feed-client';

/* -------------------------------------------------------------------------- */
/*  ServiceError                                                               */
/*  Structured error type for all service communication failures.             */
/* -------------------------------------------------------------------------- */

/** Structured error for service operations. */
export interface ServiceError {
  readonly code: 'unavailable' | 'timeout' | 'rejected' | 'unknown';
  readonly message: string;
  readonly retryable: boolean;
}

/**
 * Classify an unknown error into a structured ServiceError.
 */
export function toServiceError(err: unknown): ServiceError {
  if (err instanceof Error) {
    const msg = err.message.toLowerCase();
    if (msg.includes('timeout') || msg.includes('timed out')) {
      return { code: 'timeout', message: err.message, retryable: true };
    }
    if (msg.includes('not available') || msg.includes('unavailable') || msg.includes('not found') || msg.includes('no handler')) {
      return { code: 'unavailable', message: err.message, retryable: true };
    }
    if (msg.includes('rejected') || msg.includes('denied') || msg.includes('invalid argument') || msg.includes('bad request')) {
      return { code: 'rejected', message: err.message, retryable: false };
    }
    return { code: 'unknown', message: err.message, retryable: true };
  }
  if (typeof err === 'object' && err !== null) {
    const msg = (err as { message?: string }).message;
    if (typeof msg === 'string') return { code: 'unknown', message: msg, retryable: true };
    try { return { code: 'unknown', message: JSON.stringify(err), retryable: true }; } catch { /* fall through */ }
  }
  return { code: 'unknown', message: String(err) || 'Unknown error', retryable: true };
}

/* -------------------------------------------------------------------------- */
/*  Service Lifecycle Event Types                                              */
/* -------------------------------------------------------------------------- */

/** Service lifecycle event received on the deskmodal.services channel. */
interface ServiceLifecycleEvent {
  type: 'deskmodal.serviceEvent';
  serviceId: string;
  instanceId?: string;
  event: 'installed' | 'started' | 'ready' | 'stopped' | 'crashed' | 'uninstalled' | 'restarting';
  timestamp: number;
  error?: string;
}

/** Well-known channel and context type for service lifecycle events. */
const SERVICE_LIFECYCLE_CHANNEL = 'deskmodal.services';
const SERVICE_LIFECYCLE_CONTEXT_TYPE = 'deskmodal.serviceEvent';

/** The service ID of the price feed service. */
const PRICE_FEED_SERVICE_ID = 'deskmodal.price-feed';

/* -------------------------------------------------------------------------- */
/*  useServiceHealth                                                           */
/*  State machine tracking price-feed service availability.                    */
/*  Active health check probing + lifecycle event listener for fast detection. */
/* -------------------------------------------------------------------------- */

type ServiceHealthState = 'healthy' | 'degraded' | 'restarting' | 'failed';

export interface ServiceHealth {
  readonly state: ServiceHealthState;
  readonly message: string;
  readonly lastHealthyAt: number | null;
  /** Last service error, if any. */
  readonly lastError: ServiceError | null;
}

/** Structured log helper — routes to DeskModal logging if available. */
function structuredLog(level: 'error' | 'warn' | 'info', message: string): void {
  const win = window as { deskmodal?: { log?: (level: string, msg: string) => void } };
  if (win.deskmodal?.log) {
    win.deskmodal.log(level, message);
  }
}

/**
 * Active health check interval in milliseconds.
 * Probes the service every 5 seconds when in 'healthy' or 'restarting' state.
 * Increased from 3s to reduce noise during normal operation — price data
 * flowing on the FDC3 channel is the primary health signal.
 */
const HEALTH_CHECK_INTERVAL_MS = 5_000;

/**
 * Initial grace period before starting health checks (milliseconds).
 * Gives the service time to complete named pipe handshake + intent registration
 * before the first health check probe.
 */
const STARTUP_GRACE_MS = 10_000;

/**
 * Number of consecutive health check failures to trigger 'degraded' state.
 */
const DEGRADED_THRESHOLD = 3;

/**
 * Number of consecutive health check failures to trigger 'failed' state.
 */
const FAILED_THRESHOLD = 5;

/**
 * Tracks service health via three complementary signals:
 *   1. Passive status channel updates (FDC3 context on price channel)
 *   2. Active health check probing (3s interval)
 *   3. Service lifecycle events (deskmodal.serviceEvent on deskmodal.services)
 *
 * Lifecycle events provide near-instant crash/restart detection (<100ms),
 * complementing the polling-based approach which detects within 6-9 seconds.
 */
export function useServiceHealth(): ServiceHealth {
  const [health, setHealth] = useState<ServiceHealth>({
    state: 'restarting',
    message: 'Connecting to price feed service...',
    lastHealthyAt: null,
    lastError: null,
  });

  const consecutiveFailuresRef = useRef(0);
  const healthCheckActiveRef = useRef(true);

  // Reset health check on recovery callback
  const markHealthy = useCallback(() => {
    consecutiveFailuresRef.current = 0;
    healthCheckActiveRef.current = true;
    setHealth((prev) => ({
      state: 'healthy',
      message: '',
      lastHealthyAt: Date.now(),
      lastError: prev.state === 'healthy' ? prev.lastError : null,
    }));
  }, []);

  const markFailed = useCallback((message: string, errorMessage: string) => {
    consecutiveFailuresRef.current = FAILED_THRESHOLD;
    healthCheckActiveRef.current = false;
    const serviceError: ServiceError = {
      code: 'unavailable',
      message: errorMessage,
      retryable: true,
    };
    structuredLog('error', `[use-service-health] ${message}`);
    setHealth((prev) => ({
      state: 'failed',
      message: 'Price feed unavailable. Check service status.',
      lastHealthyAt: prev.lastHealthyAt,
      lastError: serviceError,
    }));
  }, []);

  const markRestarting = useCallback(() => {
    consecutiveFailuresRef.current = 0;
    healthCheckActiveRef.current = true;
    structuredLog('info', '[use-service-health] Service restarting');
    setHealth((prev) => ({
      state: 'restarting',
      message: 'Price feed service restarting...',
      lastHealthyAt: prev.lastHealthyAt,
      lastError: null,
    }));
  }, []);

  // Listen for passive status updates on the FDC3 channel
  useEffect(() => {
    const unsubscribe = onStatusUpdate((_status: FeedStatus) => {
      markHealthy();
    });
    return unsubscribe;
  }, [markHealthy]);

  // Listen for service lifecycle events on the deskmodal.services channel.
  // This provides near-instant crash/stop/ready detection.
  useEffect(() => {
    const fdc3 = (window as { fdc3?: {
      getOrCreateChannel?: (id: string) => Promise<{
        addContextListener: (
          contextType: string | null,
          handler: (ctx: unknown) => void,
        ) => { unsubscribe: () => void };
      }>;
    } }).fdc3;

    if (!fdc3?.getOrCreateChannel) return;

    let listener: { unsubscribe: () => void } | undefined;

    fdc3.getOrCreateChannel(SERVICE_LIFECYCLE_CHANNEL).then((channel) => {
      listener = channel.addContextListener(
        SERVICE_LIFECYCLE_CONTEXT_TYPE,
        (ctx: unknown) => {
          const event = ctx as ServiceLifecycleEvent;

          // Only react to events for the price-feed service.
          if (event.serviceId !== PRICE_FEED_SERVICE_ID) return;

          switch (event.event) {
            case 'ready':
              structuredLog('info', '[use-service-health] Lifecycle event: service ready');
              markHealthy();
              break;
            case 'crashed':
              markFailed(
                `Lifecycle event: service crashed — ${event.error ?? 'unknown error'}`,
                event.error ?? 'Service crashed unexpectedly',
              );
              break;
            case 'stopped':
              markFailed(
                'Lifecycle event: service stopped',
                'Price feed service stopped',
              );
              break;
            case 'restarting':
              markRestarting();
              break;
            case 'started':
              markRestarting();
              break;
          }
        },
      );
    }).catch(() => {
      // FDC3 channel not available — fall back to polling only.
      structuredLog('warn', '[use-service-health] Could not subscribe to lifecycle events channel');
    });

    return () => {
      listener?.unsubscribe();
    };
  }, [markHealthy, markFailed, markRestarting]);

  // Active health check probing — starts after grace period
  const graceElapsedRef = useRef(false);

  useEffect(() => {
    // Delay initial health check to give the service time to start and
    // register intent handlers via the named pipe. Without this grace period,
    // the first few health check intents arrive before the service's
    // AddIntentListener for deskmodal.HealthCheck has been processed, causing
    // false "not responding" failures.
    const graceTimeoutId = window.setTimeout(() => {
      graceElapsedRef.current = true;
    }, STARTUP_GRACE_MS);

    const intervalId = window.setInterval(() => {
      // Don't probe during startup grace period
      if (!graceElapsedRef.current) return;
      // Don't probe when failed — wait for explicit retry or channel update
      if (!healthCheckActiveRef.current) return;

      priceFeedClient.healthCheck().then((alive) => {
        if (alive) {
          markHealthy();
        } else {
          consecutiveFailuresRef.current += 1;
          const failures = consecutiveFailuresRef.current;

          if (failures >= FAILED_THRESHOLD) {
            healthCheckActiveRef.current = false; // Stop polling
            const serviceError: ServiceError = {
              code: 'unavailable',
              message: 'Price feed service not responding after multiple health checks.',
              retryable: true,
            };
            structuredLog('error', `[use-service-health] ${failures} consecutive health check failures — marking failed`);
            setHealth((prev) => ({
              state: 'failed',
              message: 'Price feed unavailable. Check service status.',
              lastHealthyAt: prev.lastHealthyAt,
              lastError: serviceError,
            }));
          } else if (failures >= DEGRADED_THRESHOLD) {
            const serviceError: ServiceError = {
              code: 'timeout',
              message: 'Price feed connection interrupted. Reconnecting...',
              retryable: true,
            };
            structuredLog('warn', `[use-service-health] ${failures} consecutive health check failures — marking degraded`);
            setHealth((prev) => ({
              state: 'degraded',
              message: 'Price feed connection interrupted. Reconnecting...',
              lastHealthyAt: prev.lastHealthyAt,
              lastError: serviceError,
            }));
          }
        }
      }).catch(() => {
        // healthCheck() already catches internally and returns false,
        // but handle edge case where the method itself fails
        consecutiveFailuresRef.current += 1;
        const failures = consecutiveFailuresRef.current;
        if (failures >= FAILED_THRESHOLD) {
          healthCheckActiveRef.current = false;
          structuredLog('error', `[use-service-health] Health check threw — marking failed`);
          setHealth((prev) => ({
            state: 'failed',
            message: 'Price feed unavailable. Check service status.',
            lastHealthyAt: prev.lastHealthyAt,
            lastError: { code: 'unavailable', message: 'Health check failed', retryable: true },
          }));
        }
      });
    }, HEALTH_CHECK_INTERVAL_MS);

    return () => {
      window.clearTimeout(graceTimeoutId);
      window.clearInterval(intervalId);
    };
  }, [markHealthy]);

  return health;
}
