import { useState, useCallback, type CSSProperties } from 'react';
import { Input, Select, Button, Dialog } from '@deskmodal/ui-components';
import type { AuthType, WsProtocol, CustomWebSocketSource } from '../hooks/use-custom-sources';

/* -------------------------------------------------------------------------- */
/*  CustomWebSocketForm                                                       */
/*  Form for configuring a custom WebSocket data source.                      */
/* -------------------------------------------------------------------------- */

export interface CustomWebSocketFormProps {
  /** Whether the dialog is open. */
  readonly open: boolean;
  /** Close the dialog. */
  readonly onOpenChange: (open: boolean) => void;
  /** Called with the completed source config when saved. */
  readonly onSave: (source: Omit<CustomWebSocketSource, 'id' | 'createdAt'>) => void;
}

/* ----- Styles ------------------------------------------------------------ */

const formStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: 'var(--ts-space-3)',
  marginTop: 'var(--ts-space-3)',
};

const fieldGroupStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: 'var(--ts-space-1)',
};

const labelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-sm)',
  fontWeight: 500,
  color: 'var(--ts-text-secondary)',
};

const rowStyle: CSSProperties = {
  display: 'flex',
  gap: 'var(--ts-space-2)',
};

const sectionLabelStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
  textTransform: 'uppercase',
  letterSpacing: '0.03em',
  marginTop: 'var(--ts-space-2)',
};

const actionsStyle: CSSProperties = {
  display: 'flex',
  justifyContent: 'flex-end',
  gap: 'var(--ts-space-2)',
  marginTop: 'var(--ts-space-2)',
};

const testResultStyle = (success: boolean): CSSProperties => ({
  fontSize: 'var(--ts-font-sm)',
  color: success ? 'var(--ts-status-success, #22c55e)' : 'var(--ts-status-error, #ef4444)',
  padding: 'var(--ts-space-2)',
  background: 'var(--ts-panel-bg)',
  borderRadius: 'var(--ts-radius-sm)',
  border: '1px solid var(--ts-panel-border)',
});

/* ----- Select options ---------------------------------------------------- */

const AUTH_OPTIONS = [
  { value: 'none', label: 'None' },
  { value: 'api-key', label: 'API Key' },
  { value: 'basic', label: 'Basic Auth' },
  { value: 'bearer', label: 'Bearer Token' },
  { value: 'custom-header', label: 'Custom Header' },
];

const PROTOCOL_OPTIONS = [
  { value: 'wss', label: 'WSS (Secure)' },
  { value: 'ws', label: 'WS (Insecure)' },
];

export function CustomWebSocketForm({
  open,
  onOpenChange,
  onSave,
}: CustomWebSocketFormProps): React.JSX.Element {
  const [name, setName] = useState('');
  const [url, setUrl] = useState('');
  const [authType, setAuthType] = useState<AuthType>('none');
  const [protocol, setProtocol] = useState<WsProtocol>('wss');
  const [apiKey, setApiKey] = useState('');
  const [apiSecret, setApiSecret] = useState('');
  const [pricePath, setPricePath] = useState('$.price');
  const [volumePath, setVolumePath] = useState('$.volume');
  const [timestampPath, setTimestampPath] = useState('$.timestamp');
  const [symbolPath, setSymbolPath] = useState('$.symbol');
  const [testing, setTesting] = useState(false);
  const [testResult, setTestResult] = useState<{ success: boolean; message: string } | null>(null);

  const isValid = name.trim().length > 0 && url.trim().length > 0;

  const handleTestConnection = useCallback(async () => {
    setTesting(true);
    setTestResult(null);

    try {
      const ws = new WebSocket(url);
      const timeout = window.setTimeout(() => {
        ws.close();
        setTestResult({ success: false, message: 'Connection timed out (5s)' });
        setTesting(false);
      }, 5000);

      ws.onopen = () => {
        window.clearTimeout(timeout);
        ws.close();
        setTestResult({ success: true, message: 'Connection successful' });
        setTesting(false);
      };

      ws.onerror = () => {
        window.clearTimeout(timeout);
        setTestResult({ success: false, message: 'Connection failed' });
        setTesting(false);
      };
    } catch {
      setTestResult({ success: false, message: 'Invalid URL' });
      setTesting(false);
    }
  }, [url]);

  const handleSave = useCallback(() => {
    const credentials: Record<string, string> = {};
    if (authType !== 'none') {
      if (apiKey) credentials['apiKey'] = apiKey;
      if (apiSecret) credentials['apiSecret'] = apiSecret;
    }

    onSave({
      type: 'websocket',
      name: name.trim(),
      url: url.trim(),
      protocol,
      authType,
      credentials,
      fieldMapping: {
        pricePath,
        volumePath,
        timestampPath,
        symbolPath,
      },
    });

    onOpenChange(false);
  }, [name, url, protocol, authType, apiKey, apiSecret, pricePath, volumePath, timestampPath, symbolPath, onSave, onOpenChange]);

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <Dialog.Content>
        <Dialog.Title>Custom WebSocket Source</Dialog.Title>
        <Dialog.Description>
          Connect to a custom WebSocket data feed with field mapping.
        </Dialog.Description>

        <div style={formStyle}>
          <div style={fieldGroupStyle}>
            <label style={labelStyle}>Name</label>
            <Input
              value={name}
              onChange={(e) => setName(e.target.value)}
              placeholder="My Custom Feed"
              size="sm"
              style={{ width: '100%' }}
            />
          </div>

          <div style={rowStyle}>
            <div style={{ ...fieldGroupStyle, flex: 1 }}>
              <label style={labelStyle}>WebSocket URL</label>
              <Input
                value={url}
                onChange={(e) => setUrl(e.target.value)}
                placeholder="wss://example.com/ws"
                size="sm"
                style={{ width: '100%' }}
              />
            </div>
            <div style={fieldGroupStyle}>
              <label style={labelStyle}>Protocol</label>
              <Select
                options={PROTOCOL_OPTIONS}
                value={protocol}
                onValueChange={(v) => setProtocol(v as WsProtocol)}
                size="sm"
              />
            </div>
          </div>

          <div style={fieldGroupStyle}>
            <label style={labelStyle}>Authentication</label>
            <Select
              options={AUTH_OPTIONS}
              value={authType}
              onValueChange={(v) => setAuthType(v as AuthType)}
              size="sm"
            />
          </div>

          {authType !== 'none' && (
            <div style={rowStyle}>
              <div style={{ ...fieldGroupStyle, flex: 1 }}>
                <label style={labelStyle}>
                  {authType === 'bearer' ? 'Token' : 'API Key'}
                </label>
                <Input
                  value={apiKey}
                  onChange={(e) => setApiKey(e.target.value)}
                  placeholder={authType === 'bearer' ? 'Bearer token...' : 'API key...'}
                  size="sm"
                  type="password"
                  style={{ width: '100%' }}
                />
              </div>
              {authType !== 'bearer' && (
                <div style={{ ...fieldGroupStyle, flex: 1 }}>
                  <label style={labelStyle}>Secret / Password</label>
                  <Input
                    value={apiSecret}
                    onChange={(e) => setApiSecret(e.target.value)}
                    placeholder="Secret..."
                    size="sm"
                    type="password"
                    style={{ width: '100%' }}
                  />
                </div>
              )}
            </div>
          )}

          <span style={sectionLabelStyle}>JSONPath Field Mapping</span>

          <div style={rowStyle}>
            <div style={{ ...fieldGroupStyle, flex: 1 }}>
              <label style={labelStyle}>Price Path</label>
              <Input
                value={pricePath}
                onChange={(e) => setPricePath(e.target.value)}
                placeholder="$.price"
                size="sm"
                style={{ width: '100%' }}
              />
            </div>
            <div style={{ ...fieldGroupStyle, flex: 1 }}>
              <label style={labelStyle}>Volume Path</label>
              <Input
                value={volumePath}
                onChange={(e) => setVolumePath(e.target.value)}
                placeholder="$.volume"
                size="sm"
                style={{ width: '100%' }}
              />
            </div>
          </div>

          <div style={rowStyle}>
            <div style={{ ...fieldGroupStyle, flex: 1 }}>
              <label style={labelStyle}>Timestamp Path</label>
              <Input
                value={timestampPath}
                onChange={(e) => setTimestampPath(e.target.value)}
                placeholder="$.timestamp"
                size="sm"
                style={{ width: '100%' }}
              />
            </div>
            <div style={{ ...fieldGroupStyle, flex: 1 }}>
              <label style={labelStyle}>Symbol Path</label>
              <Input
                value={symbolPath}
                onChange={(e) => setSymbolPath(e.target.value)}
                placeholder="$.symbol"
                size="sm"
                style={{ width: '100%' }}
              />
            </div>
          </div>

          {testResult !== null && (
            <div style={testResultStyle(testResult.success)}>
              {testResult.message}
            </div>
          )}

          <div style={actionsStyle}>
            <Button
              variant="secondary"
              size="sm"
              onClick={handleTestConnection}
              loading={testing}
              disabled={url.trim().length === 0}
            >
              Test Connection
            </Button>
            <Dialog.Close>
              <Button variant="ghost" size="sm">
                Cancel
              </Button>
            </Dialog.Close>
            <Button
              variant="primary"
              size="sm"
              onClick={handleSave}
              disabled={!isValid}
            >
              Save
            </Button>
          </div>
        </div>
      </Dialog.Content>
    </Dialog>
  );
}

CustomWebSocketForm.displayName = 'CustomWebSocketForm';
