import {
  forwardRef,
  useCallback,
  useId,
  useState,
  type CSSProperties,
  type KeyboardEvent,
  type ReactNode,
} from 'react';
import { ChevronDown, ChevronRight } from 'lucide-react';

export interface PanelProps {
  /** Panel header title */
  title: string;
  /** Actions slot rendered at the right side of the header */
  actions?: ReactNode;
  /** Whether the panel can be collapsed */
  collapsible?: boolean;
  /** Default collapsed state (uncontrolled) */
  defaultCollapsed?: boolean;
  /** Callback when collapsed state changes */
  onCollapsedChange?: (collapsed: boolean) => void;
  /** Panel content */
  children: ReactNode;
  /** Additional class name */
  className?: string;
}

const rootStyle: CSSProperties = {
  background: 'var(--ts-panel-bg)',
  border: '1px solid var(--ts-panel-border)',
  borderRadius: 'var(--ts-radius-sm)',
  overflow: 'hidden',
};

const headerStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  height: 'var(--ts-panel-header-height)',
  padding: `0 var(--ts-panel-header-padding-x)`,
  background: 'var(--ts-panel-header-bg)',
  color: 'var(--ts-panel-header-text)',
  fontSize: 'var(--ts-font-md)',
  fontWeight: 'var(--ts-font-weight-medium)' as unknown as number,
  gap: 'var(--ts-space-2)',
  userSelect: 'none',
  borderBottom: '1px solid var(--ts-panel-border)',
};

const titleStyle: CSSProperties = {
  flex: 1,
  overflow: 'hidden',
  textOverflow: 'ellipsis',
  whiteSpace: 'nowrap',
};

const chevronStyle: CSSProperties = {
  flexShrink: 0,
  color: 'var(--ts-panel-header-text-secondary)',
  transition: `transform var(--ts-duration-normal) ease`,
};

const contentWrapperCollapsedStyle: CSSProperties = {
  overflow: 'hidden',
  transition: `grid-template-rows var(--ts-duration-normal) ease`,
  display: 'grid',
  gridTemplateRows: '0fr',
};

const contentWrapperExpandedStyle: CSSProperties = {
  ...contentWrapperCollapsedStyle,
  gridTemplateRows: '1fr',
};

const contentInnerStyle: CSSProperties = {
  overflow: 'hidden',
};

const contentStyle: CSSProperties = {
  padding: 'var(--ts-panel-content-padding)',
};

export const Panel = forwardRef<HTMLDivElement, PanelProps>(
  function Panel(
    {
      title,
      actions,
      collapsible = false,
      defaultCollapsed = false,
      onCollapsedChange,
      children,
      className,
    },
    ref,
  ) {
    const [collapsed, setCollapsed] = useState(defaultCollapsed);
    const contentId = useId();
    const headerId = useId();

    const toggleCollapsed = useCallback(() => {
      if (!collapsible) return;
      const next = !collapsed;
      setCollapsed(next);
      onCollapsedChange?.(next);
    }, [collapsible, collapsed, onCollapsedChange]);

    const handleKeyDown = useCallback(
      (event: KeyboardEvent<HTMLDivElement>) => {
        if (event.key === 'Enter' || event.key === ' ') {
          event.preventDefault();
          toggleCollapsed();
        }
      },
      [toggleCollapsed],
    );

    const headerProps = collapsible
      ? {
          role: 'button' as const,
          tabIndex: 0,
          'aria-expanded': !collapsed,
          'aria-controls': contentId,
          onClick: toggleCollapsed,
          onKeyDown: handleKeyDown,
          style: { ...headerStyle, cursor: 'pointer' },
        }
      : {
          style: headerStyle,
        };

    return (
      <div
        ref={ref}
        className={className}
        style={rootStyle}
        data-collapsed={collapsed ? '' : undefined}
      >
        <div id={headerId} {...headerProps}>
          {collapsible && (
            <span style={chevronStyle} aria-hidden="true">
              {collapsed ? (
                <ChevronRight size={14} />
              ) : (
                <ChevronDown size={14} />
              )}
            </span>
          )}
          <span style={titleStyle}>{title}</span>
          {actions && (
            <div
              style={{ display: 'flex', alignItems: 'center', gap: 'var(--ts-space-1)' }}
              onClick={(e) => e.stopPropagation()}
              onKeyDown={(e) => e.stopPropagation()}
            >
              {actions}
            </div>
          )}
        </div>
        <div
          id={contentId}
          role="region"
          aria-labelledby={headerId}
          style={collapsed ? contentWrapperCollapsedStyle : contentWrapperExpandedStyle}
        >
          <div style={contentInnerStyle}>
            <div style={contentStyle}>{children}</div>
          </div>
        </div>
      </div>
    );
  },
);
