import { useCallback, useRef } from "react";
import type { Context } from "../fdc3-types";
import { getDeskModalAPI } from "../desk/desk-detection";
import { useFdc3 } from "./use-fdc3";

/** Options for sending a notification. */
export interface NotificationOptions {
  /** Notification priority level. */
  priority?: "critical" | "normal" | "low";
  /** ID of the source app that generated the notification. */
  sourceApp?: string;
  /** Plugin-defined category string for grouping in the notification center. */
  category?: string;
  /** Hex color for the notification indicator dot (DeskModal-only). */
  indicatorColor?: string;
  /** Auto-dismiss duration in milliseconds (DeskModal-only). */
  duration?: number;
  /** Action buttons rendered with the notification (DeskModal-only). */
  actions?: Array<{ label: string; actionType: string; payload?: string }>;
}

/** Return type for the useNotify hook. */
export interface UseNotifyResult {
  /**
   * Send a notification.
   *
   * Layered delivery:
   * 1. DeskModal notification API (enhanced: OS-native, actions, categories)
   * 2. FDC3 broadcast of a notification context (standard: any desktop agent can handle)
   *
   * Returns the DeskModal notification ID if delivered via DeskModal, 'fdc3' if
   * delivered via FDC3 broadcast, or null if neither is available.
   */
  notify: (
    title: string,
    body: string,
    options?: NotificationOptions,
  ) => Promise<string | null>;
  /** Dismiss an active notification by ID. DeskModal-only — no-op on FDC3. */
  dismiss: (id: string) => Promise<void>;
}

/**
 * Notification hook with layered delivery: DeskModal enhanced → FDC3 standard.
 *
 * When running on DeskModal, uses the native notification center for the
 * richest experience (actions, categories, OS integration).
 * When on any other FDC3 desktop agent, broadcasts a `deskmodal.notification`
 * context on the alerts channel — the agent can surface it however it chooses.
 * Callers should still show an in-app toast as their own local fallback.
 */
export function useNotify(): UseNotifyResult {
  const fdc3 = useFdc3();
  const fdc3Ref = useRef(fdc3);
  fdc3Ref.current = fdc3;

  const notify = useCallback(
    async (
      title: string,
      body: string,
      options?: NotificationOptions,
    ): Promise<string | null> => {
      // Layer 1: DeskModal enhanced notification
      const api = getDeskModalAPI();
      if (api?.notification) {
        try {
          return await api.notification.send(title, body, options);
        } catch {
          // Fall through to FDC3
        }
      }

      // Layer 2: FDC3 broadcast — any desktop agent can handle
      const agent = fdc3Ref.current;
      if (agent) {
        try {
          const notificationContext: Context = {
            type: "deskmodal.notification",
            name: title,
            id: options?.sourceApp ? { sourceApp: options.sourceApp } : undefined,
          };
          // Attach metadata as context properties
          const ctx = notificationContext as unknown as Record<string, unknown>;
          ctx["deskmodal.body"] = body;
          if (options?.priority) {
            ctx["deskmodal.priority"] = options.priority;
          }
          if (options?.category) {
            ctx["deskmodal.category"] = options.category;
          }

          await agent.broadcast(notificationContext);
          return "fdc3";
        } catch {
          // FDC3 broadcast failed — return null
        }
      }

      return null;
    },
    [],
  );

  const dismiss = useCallback(async (id: string): Promise<void> => {
    const api = getDeskModalAPI();
    if (!api?.notification) return;
    try {
      await api.notification.dismiss(id);
    } catch {
      // Dismiss failure — degrade silently
    }
  }, []);

  return { notify, dismiss };
}

/**
 * @deprecated Use `useNotify()` instead. This alias exists for backwards compatibility.
 */
export const useDeskModalNotifications = useNotify;
