import {
  useRef,
  useState,
  useCallback,
  useMemo,
  type CSSProperties,
  type MouseEvent as ReactMouseEvent,
  type ReactNode,
} from 'react';
import {
  useReactTable,
  getCoreRowModel,
  getSortedRowModel,
  getFilteredRowModel,
  flexRender,
  type ColumnDef,
  type SortingState,
  type ColumnSizingState,
  type Header,
  type ColumnResizeMode,
  type FilterFn,
} from '@tanstack/react-table';

export type { ColumnSizingState } from '@tanstack/react-table';
import { useVirtualizer } from '@tanstack/react-virtual';
import { ArrowUp, ArrowDown, ArrowUpDown } from 'lucide-react';

/* -------------------------------------------------------------------------- */
/*  DataGrid                                                                   */
/*  High-performance table wrapping TanStack Table + TanStack Virtual.         */
/*  Uses --ts-data-* tokens for all styling.                                   */
/* -------------------------------------------------------------------------- */

export interface DataGridProps<TData> {
  /** Column definitions for TanStack Table. */
  columns: ColumnDef<TData, unknown>[];
  /** Data rows. */
  data: TData[];
  /** Called when a row is clicked, with the row data. */
  onRowClick?: (row: TData) => void;
  /** ID of the currently selected row. Matches the row's `id` field if present. */
  selectedRowId?: string;
  /** Enable sorting on column headers. */
  sortable?: boolean;
  /** Enable virtualized row rendering for large datasets. */
  virtualizeRows?: boolean;
  /** Height of each row in pixels. */
  rowHeight?: number;
  /** Additional CSS class name on the root element. */
  className?: string;
  /** When true, renders a filter input row below the header. */
  enableFiltering?: boolean;
  /** Called when column sizing changes (for persistence). */
  onColumnSizingChange?: (sizing: ColumnSizingState) => void;
  /** Initial column sizing state (restored from persistence). */
  initialColumnSizing?: ColumnSizingState;
  /** Rendered when data array is empty. */
  emptyState?: ReactNode;
  /** Global filter value — matched against all columns. */
  globalFilter?: string;
  /** Custom global filter function. */
  globalFilterFn?: FilterFn<TData>;
}

/* ----- Style injection for hover/resize states --------------------------- */

const DATAGRID_STYLE_ID = 'ts-datagrid-styles';

function ensureDataGridStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(DATAGRID_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = DATAGRID_STYLE_ID;
  sheet.textContent = `
    [data-ts-datagrid-row]:hover {
      background: var(--ts-data-row-bg-hover) !important;
    }
    [data-ts-datagrid-header-cell]:hover [data-ts-datagrid-resize-handle] {
      opacity: 1;
      background: var(--ts-data-header-resize-handle-hover);
    }
    [data-ts-datagrid-resize-handle]:hover,
    [data-ts-datagrid-resize-handle][data-resizing] {
      opacity: 1;
      background: var(--ts-data-header-resize-handle-hover);
    }
    [data-ts-datagrid-header-cell][data-sortable]:hover {
      cursor: pointer;
    }
    [data-ts-datagrid-header-cell][data-sortable]:hover [data-ts-sort-icon] {
      color: var(--ts-data-header-sort-icon-active);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureDataGridStyles();
}

/* ----- Static styles ----------------------------------------------------- */

const rootStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  overflow: 'hidden',
  width: '100%',
};

const tableStyle: CSSProperties = {
  display: 'grid',
  width: '100%',
};

const headerRowStyle: CSSProperties = {
  display: 'flex',
  position: 'sticky',
  top: 0,
  zIndex: 1,
  background: 'var(--ts-data-header-bg)',
  borderBottom: '1px solid var(--ts-data-header-border)',
};

const headerCellBaseStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: '4px',
  height: 'var(--ts-data-header-height)',
  padding: '0 var(--ts-data-header-padding-x)',
  color: 'var(--ts-data-header-text)',
  fontSize: 'var(--ts-data-header-font-size)',
  fontWeight: 'var(--ts-data-header-font-weight)' as unknown as number,
  userSelect: 'none',
  position: 'relative',
  overflow: 'hidden',
  whiteSpace: 'nowrap',
  boxSizing: 'border-box',
};

const resizeHandleStyle: CSSProperties = {
  position: 'absolute',
  right: 0,
  top: 0,
  height: '100%',
  width: '4px',
  cursor: 'col-resize',
  opacity: 0,
  background: 'var(--ts-data-header-resize-handle)',
  transition: 'opacity 150ms, background 150ms',
  touchAction: 'none',
};

const sortIconStyle: CSSProperties = {
  flexShrink: 0,
  color: 'var(--ts-data-header-sort-icon)',
  transition: 'color 150ms',
};

const sortIconActiveStyle: CSSProperties = {
  flexShrink: 0,
  color: 'var(--ts-data-header-sort-icon-active)',
};

const bodyContainerStyle: CSSProperties = {
  overflow: 'auto',
  flex: 1,
};

const rowBaseStyle: CSSProperties = {
  display: 'flex',
  borderBottom: '1px solid var(--ts-data-row-border)',
  background: 'var(--ts-data-row-bg)',
  cursor: 'pointer',
  transition: 'background 100ms',
};

const selectedRowStyle: CSSProperties = {
  background: 'var(--ts-data-row-bg-selected)',
};

const cellBaseStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  padding: '0 var(--ts-data-row-padding-x)',
  fontFamily: 'var(--ts-data-cell-font)',
  fontSize: 'var(--ts-data-cell-font-size)',
  color: 'var(--ts-data-row-text)',
  overflow: 'hidden',
  whiteSpace: 'nowrap',
  textOverflow: 'ellipsis',
  boxSizing: 'border-box',
};

const filterRowStyle: CSSProperties = {
  display: 'flex',
  background: 'var(--ts-data-header-bg)',
  borderBottom: '1px solid var(--ts-data-header-border)',
  padding: '2px 0',
};

const filterInputCellStyle: CSSProperties = {
  width: '100%',
  padding: '2px 4px',
  fontSize: 'var(--ts-font-xs, 11px)',
  background: 'var(--ts-surface-1, #111827)',
  border: '1px solid var(--ts-border-subtle, #374151)',
  borderRadius: '2px',
  color: 'var(--ts-text-primary, #e5e7eb)',
  outline: 'none',
  boxSizing: 'border-box',
};

const emptyContainerStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'center',
  padding: 'var(--ts-space-6, 24px)',
  flex: 1,
};

const COLUMN_RESIZE_MODE: ColumnResizeMode = 'onChange';

function SortIcon({ direction }: { direction: false | 'asc' | 'desc' }) {
  if (direction === 'asc') {
    return <ArrowUp size={12} style={sortIconActiveStyle} data-ts-sort-icon="" aria-label="Sorted ascending" />;
  }
  if (direction === 'desc') {
    return <ArrowDown size={12} style={sortIconActiveStyle} data-ts-sort-icon="" aria-label="Sorted descending" />;
  }
  return <ArrowUpDown size={12} style={sortIconStyle} data-ts-sort-icon="" aria-label="Unsorted" />;
}

export function DataGrid<TData>({
  columns,
  data,
  onRowClick,
  selectedRowId,
  sortable = false,
  virtualizeRows = true,
  rowHeight = 28,
  className,
  enableFiltering = false,
  onColumnSizingChange,
  initialColumnSizing,
  emptyState,
  globalFilter,
  globalFilterFn,
}: DataGridProps<TData>) {
  const [sorting, setSorting] = useState<SortingState>([]);
  const [columnFilters, setColumnFilters] = useState<Record<string, string>>({});
  const [columnSizing, setColumnSizing] = useState<ColumnSizingState>(initialColumnSizing ?? {});
  const scrollContainerRef = useRef<HTMLDivElement>(null);

  const handleColumnSizingChange = useCallback(
    (updaterOrValue: ColumnSizingState | ((prev: ColumnSizingState) => ColumnSizingState)) => {
      setColumnSizing((prev) => {
        const next = typeof updaterOrValue === 'function' ? updaterOrValue(prev) : updaterOrValue;
        onColumnSizingChange?.(next);
        return next;
      });
    },
    [onColumnSizingChange],
  );

  const columnFilterFn = useMemo<FilterFn<TData> | undefined>(() => {
    if (!enableFiltering) return undefined;
    return (row, columnId) => {
      const filterValue = columnFilters[columnId];
      if (!filterValue) return true;
      const cellValue = String(row.getValue(columnId) ?? '').toLowerCase();
      return cellValue.includes(filterValue.toLowerCase());
    };
  }, [enableFiltering, columnFilters]);

  const table = useReactTable({
    data,
    columns,
    state: {
      sorting,
      columnSizing,
      ...(globalFilter !== undefined ? { globalFilter } : {}),
    },
    onSortingChange: sortable ? setSorting : undefined,
    onColumnSizingChange: handleColumnSizingChange,
    getCoreRowModel: getCoreRowModel(),
    getSortedRowModel: sortable ? getSortedRowModel() : undefined,
    getFilteredRowModel: (enableFiltering || globalFilter !== undefined) ? getFilteredRowModel() : undefined,
    columnResizeMode: COLUMN_RESIZE_MODE,
    enableSorting: sortable,
    enableColumnFilters: enableFiltering,
    enableGlobalFilter: globalFilter !== undefined,
    globalFilterFn: globalFilterFn ?? 'includesString',
    filterFns: columnFilterFn ? { columnFilterFn } : undefined,
  });

  const { rows } = table.getRowModel();

  const virtualizer = useVirtualizer({
    count: rows.length,
    getScrollElement: () => scrollContainerRef.current,
    estimateSize: () => rowHeight,
    overscan: 10,
    enabled: virtualizeRows,
  });

  const handleHeaderClick = useCallback(
    (header: Header<TData, unknown>) => {
      if (!sortable || !header.column.getCanSort()) return;
      header.column.toggleSorting();
    },
    [sortable],
  );

  const handleResizeMouseDown = useCallback(
    (e: ReactMouseEvent, header: Header<TData, unknown>) => {
      e.stopPropagation();
      header.getResizeHandler()(e);
    },
    [],
  );

  const columnSizeVars = useMemo(() => {
    const headers = table.getFlatHeaders();
    const colSizes: Record<string, string> = {};
    for (const header of headers) {
      colSizes[`--col-${header.id}-size`] = `${header.getSize()}px`;
    }
    return colSizes;
  }, [table.getState().columnSizingInfo, table.getState().columnSizing]);

  const virtualItems = virtualizeRows ? virtualizer.getVirtualItems() : null;
  const totalSize = virtualizeRows ? virtualizer.getTotalSize() : 0;

  return (
    <div
      data-ts-datagrid=""
      className={className}
      style={rootStyle}
    >
      {/* Table container with column size variables */}
      <div style={{ ...tableStyle, ...columnSizeVars }}>
        {/* Header */}
        <div style={headerRowStyle} role="row" data-ts-datagrid-header="">
          {table.getFlatHeaders().map((header) => {
            const canSort = sortable && header.column.getCanSort();
            const sortDir = header.column.getIsSorted();
            return (
              <div
                key={header.id}
                role="columnheader"
                data-ts-datagrid-header-cell=""
                {...(canSort ? { 'data-sortable': '' } : {})}
                style={{
                  ...headerCellBaseStyle,
                  width: `var(--col-${header.id}-size)`,
                }}
                onClick={() => handleHeaderClick(header)}
                onKeyDown={(e) => {
                  if (canSort && (e.key === 'Enter' || e.key === ' ')) {
                    e.preventDefault();
                    handleHeaderClick(header);
                  }
                }}
                tabIndex={canSort ? 0 : undefined}
                aria-sort={
                  sortDir === 'asc'
                    ? 'ascending'
                    : sortDir === 'desc'
                      ? 'descending'
                      : canSort
                        ? 'none'
                        : undefined
                }
              >
                {header.isPlaceholder
                  ? null
                  : flexRender(header.column.columnDef.header, header.getContext())}
                {canSort && <SortIcon direction={sortDir} />}
                <div
                  data-ts-datagrid-resize-handle=""
                  {...(header.column.getIsResizing() ? { 'data-resizing': '' } : {})}
                  style={resizeHandleStyle}
                  onMouseDown={(e) => handleResizeMouseDown(e, header)}
                  onTouchStart={header.getResizeHandler()}
                />
              </div>
            );
          })}
        </div>

        {/* Filter row */}
        {enableFiltering && (
          <div style={filterRowStyle} role="row" data-ts-datagrid-filter-row="">
            {table.getFlatHeaders().map((header) => (
              <div
                key={header.id}
                style={{
                  width: `var(--col-${header.id}-size)`,
                  padding: '0 var(--ts-data-header-padding-x, 8px)',
                  boxSizing: 'border-box',
                }}
              >
                <input
                  type="text"
                  placeholder="Filter..."
                  value={columnFilters[header.id] ?? ''}
                  onChange={(e) => {
                    const val = e.target.value;
                    setColumnFilters((prev) => ({ ...prev, [header.id]: val }));
                    header.column.setFilterValue(val || undefined);
                  }}
                  style={filterInputCellStyle}
                  data-ts-datagrid-filter-input=""
                />
              </div>
            ))}
          </div>
        )}

        {/* Body */}
        <div
          ref={scrollContainerRef}
          style={bodyContainerStyle}
          data-ts-datagrid-body=""
        >
          {data.length === 0 && emptyState ? (
            <div style={emptyContainerStyle}>{emptyState}</div>
          ) : rows.length === 0 && emptyState ? (
            <div style={emptyContainerStyle}>{emptyState}</div>
          ) : virtualizeRows ? (
            <div style={{ height: `${totalSize}px`, position: 'relative' }}>
              {virtualItems?.map((virtualRow) => {
                const row = rows[virtualRow.index];
                if (!row) return null;
                const rowData = row.original;
                const isSelected = selectedRowId !== undefined && typeof rowData === 'object' && rowData !== null && 'id' in rowData && (rowData as Record<string, unknown>).id === selectedRowId;
                return (
                  <div
                    key={row.id}
                    role="row"
                    data-ts-datagrid-row=""
                    {...(isSelected ? { 'data-selected': '' } : {})}
                    style={{
                      ...rowBaseStyle,
                      ...(isSelected ? selectedRowStyle : {}),
                      height: `${rowHeight}px`,
                      position: 'absolute',
                      top: 0,
                      left: 0,
                      width: '100%',
                      transform: `translateY(${virtualRow.start}px)`,
                    }}
                    onClick={() => onRowClick?.(rowData)}
                    onKeyDown={(e) => {
                      if (e.key === 'Enter' || e.key === ' ') {
                        e.preventDefault();
                        onRowClick?.(rowData);
                      }
                    }}
                    tabIndex={onRowClick ? 0 : undefined}
                  >
                    {row.getVisibleCells().map((cell) => (
                      <div
                        key={cell.id}
                        role="cell"
                        data-ts-datagrid-cell=""
                        style={{
                          ...cellBaseStyle,
                          width: `var(--col-${cell.column.id}-size)`,
                          height: `${rowHeight}px`,
                        }}
                      >
                        {flexRender(cell.column.columnDef.cell, cell.getContext())}
                      </div>
                    ))}
                  </div>
                );
              })}
            </div>
          ) : (
            rows.map((row) => {
              const rowData = row.original;
              const isSelected = selectedRowId !== undefined && typeof rowData === 'object' && rowData !== null && 'id' in rowData && (rowData as Record<string, unknown>).id === selectedRowId;
              return (
                <div
                  key={row.id}
                  role="row"
                  data-ts-datagrid-row=""
                  {...(isSelected ? { 'data-selected': '' } : {})}
                  style={{
                    ...rowBaseStyle,
                    ...(isSelected ? selectedRowStyle : {}),
                    height: `${rowHeight}px`,
                  }}
                  onClick={() => onRowClick?.(rowData)}
                  onKeyDown={(e) => {
                    if (e.key === 'Enter' || e.key === ' ') {
                      e.preventDefault();
                      onRowClick?.(rowData);
                    }
                  }}
                  tabIndex={onRowClick ? 0 : undefined}
                >
                  {row.getVisibleCells().map((cell) => (
                    <div
                      key={cell.id}
                      role="cell"
                      data-ts-datagrid-cell=""
                      style={{
                        ...cellBaseStyle,
                        width: `var(--col-${cell.column.id}-size)`,
                        height: `${rowHeight}px`,
                      }}
                    >
                      {flexRender(cell.column.columnDef.cell, cell.getContext())}
                    </div>
                  ))}
                </div>
              );
            })
          )}
        </div>
      </div>
    </div>
  );
}

DataGrid.displayName = 'DataGrid';
