import { forwardRef, type CSSProperties, type InputHTMLAttributes, type ReactNode } from 'react';

/* -------------------------------------------------------------------------- */
/*  Input                                                                     */
/*  Text input with prefix/suffix slots, error, and size variants.            */
/*  Uses --ts-input-* tokens.                                                 */
/* -------------------------------------------------------------------------- */

type InputSize = 'sm' | 'md' | 'lg';

export interface InputProps extends Omit<InputHTMLAttributes<HTMLInputElement>, 'size' | 'prefix'> {
  /** Input size controlling height. */
  size?: InputSize;
  /** Whether the input shows an error border. */
  error?: boolean;
  /** Slot rendered before the input (icon, label, etc.). */
  prefix?: ReactNode;
  /** Slot rendered after the input (icon, unit, etc.). */
  suffix?: ReactNode;
}

/* ----- Style injection for hover/focus/error states ---------------------- */

const INPUT_STYLE_ID = 'ts-input-styles';

function ensureInputStyles(): void {
  if (typeof document === 'undefined') return;
  if (document.getElementById(INPUT_STYLE_ID)) return;
  const sheet = document.createElement('style');
  sheet.id = INPUT_STYLE_ID;
  sheet.textContent = `
    [data-ts-input-wrapper]:not([data-disabled]):hover {
      border-color: var(--ts-input-border-hover);
    }
    [data-ts-input-wrapper]:not([data-disabled]):focus-within {
      border-color: var(--ts-input-border-focus);
      outline: 1px solid var(--ts-input-border-focus);
      outline-offset: -1px;
    }
    [data-ts-input-wrapper][data-error]:not([data-disabled]) {
      border-color: var(--ts-input-border-error);
    }
    [data-ts-input-wrapper][data-error]:not([data-disabled]):focus-within {
      border-color: var(--ts-input-border-error);
      outline-color: var(--ts-input-border-error);
    }
    [data-ts-input-wrapper][data-disabled] {
      background: var(--ts-input-bg-disabled);
      color: var(--ts-input-text-disabled);
      cursor: not-allowed;
    }
    [data-ts-input-field]::placeholder {
      color: var(--ts-input-placeholder);
    }
  `;
  document.head.appendChild(sheet);
}

if (typeof document !== 'undefined') {
  ensureInputStyles();
}

/* ----- Size styles ------------------------------------------------------- */

const SIZE_HEIGHTS: Record<InputSize, string> = {
  sm: 'var(--ts-input-height-sm)',
  md: 'var(--ts-input-height-md)',
  lg: 'var(--ts-input-height-lg)',
};

const wrapperBaseStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  gap: 'var(--ts-space-1)',
  background: 'var(--ts-input-bg)',
  color: 'var(--ts-input-text)',
  border: '1px solid var(--ts-input-border)',
  borderRadius: 'var(--ts-input-radius)',
  padding: '0 var(--ts-input-padding-x)',
  fontSize: 'var(--ts-input-font-size)',
  fontFamily: 'inherit',
  boxSizing: 'border-box',
  transition: 'border-color 150ms',
};

const inputFieldStyle: CSSProperties = {
  all: 'unset',
  flex: 1,
  minWidth: 0,
  height: '100%',
  color: 'inherit',
  fontSize: 'inherit',
  fontFamily: 'inherit',
};

const slotStyle: CSSProperties = {
  display: 'inline-flex',
  alignItems: 'center',
  flexShrink: 0,
  color: 'var(--ts-text-tertiary)',
};

export const Input = forwardRef<HTMLInputElement, InputProps>(
  function Input(
    { size = 'md', error = false, prefix, suffix, disabled, style, ...rest },
    ref,
  ) {
    return (
      <div
        data-ts-input-wrapper=""
        {...(error ? { 'data-error': '' } : {})}
        {...(disabled ? { 'data-disabled': '' } : {})}
        style={{
          ...wrapperBaseStyle,
          height: SIZE_HEIGHTS[size],
          ...style,
        }}
      >
        {prefix !== undefined && <span style={slotStyle}>{prefix}</span>}
        <input
          ref={ref}
          data-ts-input-field=""
          disabled={disabled}
          style={inputFieldStyle}
          {...rest}
        />
        {suffix !== undefined && <span style={slotStyle}>{suffix}</span>}
      </div>
    );
  },
);

Input.displayName = 'Input';
