import { useState, useMemo, type CSSProperties } from 'react';
import { Dialog, Tabs, Input, Badge, Button, ScrollArea } from '@deskmodal/ui-components';
import { Search } from 'lucide-react';
import type { ExchangeId } from '@deskmodal/data-layer';

/* -------------------------------------------------------------------------- */
/*  AddExchangeBrowser                                                        */
/*  Dialog for browsing and enabling exchange connections.                     */
/* -------------------------------------------------------------------------- */

export interface AddExchangeBrowserProps {
  /** Whether the dialog is open. */
  readonly open: boolean;
  /** Close the dialog. */
  readonly onOpenChange: (open: boolean) => void;
  /** Set of currently connected exchange IDs. */
  readonly connectedExchangeIds: ReadonlySet<string>;
  /** Enable (connect to) an exchange. */
  readonly onEnable: (exchangeId: ExchangeId) => void;
  /** Open the custom WebSocket form. */
  readonly onAddCustomWebSocket?: () => void;
  /** Open the custom REST API form. */
  readonly onAddCustomRestApi?: () => void;
  /** Open the file import form. */
  readonly onAddFileImport?: () => void;
}

/* ----- Exchange catalog -------------------------------------------------- */

type ExchangeCategory = 'cex' | 'dex' | 'data-provider' | 'custom';

interface CatalogEntry {
  id: ExchangeId;
  name: string;
  category: ExchangeCategory;
  description: string;
}

const EXCHANGE_CATALOG: CatalogEntry[] = [
  { id: 'binance', name: 'Binance', category: 'cex', description: 'Largest crypto exchange by volume. WebSocket public tickers, orderbooks, trades.' },
  { id: 'coinbase', name: 'Coinbase', category: 'cex', description: 'US-regulated exchange. Real-time market data via WebSocket feed.' },
  { id: 'bybit', name: 'Bybit', category: 'cex', description: 'Spot and derivatives exchange. V5 public WebSocket endpoint.' },
  { id: 'okx', name: 'OKX', category: 'cex', description: 'Multi-chain exchange with spot, futures, options. Public WebSocket V5.' },
  { id: 'uniswap-v3', name: 'Uniswap V3', category: 'dex', description: 'Ethereum DEX. On-chain pool data via Subgraph and RPC.' },
  { id: 'raydium', name: 'Raydium', category: 'dex', description: 'Solana DEX. AMM pool data via on-chain programs.' },
];

/* ----- Styles ------------------------------------------------------------ */

const contentInnerStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: 'var(--ts-space-3)',
  marginTop: 'var(--ts-space-3)',
};

const searchRowStyle: CSSProperties = {
  padding: '0',
};

const listStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: 'var(--ts-space-2)',
  maxHeight: 400,
};

const entryStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  gap: 'var(--ts-space-3)',
  padding: 'var(--ts-space-3)',
  background: 'var(--ts-panel-bg)',
  border: '1px solid var(--ts-panel-border)',
  borderRadius: 'var(--ts-radius-sm)',
};

const entryInfoStyle: CSSProperties = {
  flex: 1,
  display: 'flex',
  flexDirection: 'column',
  gap: 'var(--ts-space-1)',
  minWidth: 0,
};

const entryNameStyle: CSSProperties = {
  fontSize: 'var(--ts-font-md)',
  fontWeight: 500,
  color: 'var(--ts-text-primary)',
};

const entryDescStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
  lineHeight: 1.4,
};

const customActionsStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: 'var(--ts-space-2)',
  padding: 'var(--ts-space-3)',
};

const customActionRowStyle: CSSProperties = {
  display: 'flex',
  alignItems: 'center',
  justifyContent: 'space-between',
  padding: 'var(--ts-space-3)',
  background: 'var(--ts-panel-bg)',
  border: '1px solid var(--ts-panel-border)',
  borderRadius: 'var(--ts-radius-sm)',
};

const customActionLabelStyle: CSSProperties = {
  display: 'flex',
  flexDirection: 'column',
  gap: 'var(--ts-space-1)',
};

const customActionTitleStyle: CSSProperties = {
  fontSize: 'var(--ts-font-md)',
  fontWeight: 500,
  color: 'var(--ts-text-primary)',
};

const customActionDescStyle: CSSProperties = {
  fontSize: 'var(--ts-font-xs)',
  color: 'var(--ts-text-tertiary)',
};

/* ----- Component --------------------------------------------------------- */

export function AddExchangeBrowser({
  open,
  onOpenChange,
  connectedExchangeIds,
  onEnable,
  onAddCustomWebSocket,
  onAddCustomRestApi,
  onAddFileImport,
}: AddExchangeBrowserProps): React.JSX.Element {
  const [searchFilter, setSearchFilter] = useState('');
  const [activeTab, setActiveTab] = useState<string>('cex');

  const filteredEntries = useMemo(() => {
    const query = searchFilter.toLowerCase().trim();
    return EXCHANGE_CATALOG.filter((entry) => {
      const matchesCategory = activeTab === 'custom' || entry.category === activeTab;
      const matchesSearch =
        query.length === 0 ||
        entry.name.toLowerCase().includes(query) ||
        entry.description.toLowerCase().includes(query);
      return matchesCategory && matchesSearch;
    });
  }, [searchFilter, activeTab]);

  return (
    <Dialog open={open} onOpenChange={onOpenChange}>
      <Dialog.Content>
        <Dialog.Title>Add Exchange</Dialog.Title>
        <Dialog.Description>
          Browse available exchanges and data sources to connect.
        </Dialog.Description>

        <div style={contentInnerStyle}>
          <div style={searchRowStyle}>
            <Input
              placeholder="Filter exchanges..."
              value={searchFilter}
              onChange={(e) => setSearchFilter(e.target.value)}
              prefix={<Search size={14} />}
              size="sm"
              style={{ width: '100%' }}
            />
          </div>

          <Tabs value={activeTab} onValueChange={setActiveTab}>
            <Tabs.List>
              <Tabs.Trigger value="cex">CEX</Tabs.Trigger>
              <Tabs.Trigger value="dex">DEX</Tabs.Trigger>
              <Tabs.Trigger value="data-provider">Data Providers</Tabs.Trigger>
              <Tabs.Trigger value="custom">Custom</Tabs.Trigger>
            </Tabs.List>

            <Tabs.Content value="cex">
              <ExchangeList
                entries={filteredEntries}
                connectedIds={connectedExchangeIds}
                onEnable={onEnable}
              />
            </Tabs.Content>

            <Tabs.Content value="dex">
              <ExchangeList
                entries={filteredEntries}
                connectedIds={connectedExchangeIds}
                onEnable={onEnable}
              />
            </Tabs.Content>

            <Tabs.Content value="data-provider">
              <div style={{ padding: 'var(--ts-space-4)', color: 'var(--ts-text-tertiary)', fontSize: 'var(--ts-font-sm)', textAlign: 'center' }}>
                Third-party data providers coming soon.
              </div>
            </Tabs.Content>

            <Tabs.Content value="custom">
              <div style={customActionsStyle}>
                <div style={customActionRowStyle}>
                  <div style={customActionLabelStyle}>
                    <span style={customActionTitleStyle}>Custom WebSocket</span>
                    <span style={customActionDescStyle}>Connect to any WebSocket data feed</span>
                  </div>
                  <Button
                    variant="secondary"
                    size="sm"
                    onClick={() => {
                      onAddCustomWebSocket?.();
                      onOpenChange(false);
                    }}
                  >
                    Configure
                  </Button>
                </div>
                <div style={customActionRowStyle}>
                  <div style={customActionLabelStyle}>
                    <span style={customActionTitleStyle}>Custom REST API</span>
                    <span style={customActionDescStyle}>Poll a REST endpoint on an interval</span>
                  </div>
                  <Button
                    variant="secondary"
                    size="sm"
                    onClick={() => {
                      onAddCustomRestApi?.();
                      onOpenChange(false);
                    }}
                  >
                    Configure
                  </Button>
                </div>
                <div style={customActionRowStyle}>
                  <div style={customActionLabelStyle}>
                    <span style={customActionTitleStyle}>File Import</span>
                    <span style={customActionDescStyle}>Import data from CSV, JSON, or Parquet</span>
                  </div>
                  <Button
                    variant="secondary"
                    size="sm"
                    onClick={() => {
                      onAddFileImport?.();
                      onOpenChange(false);
                    }}
                  >
                    Import
                  </Button>
                </div>
              </div>
            </Tabs.Content>
          </Tabs>
        </div>
      </Dialog.Content>
    </Dialog>
  );
}

/* ----- Exchange list subcomponent ---------------------------------------- */

interface ExchangeListProps {
  entries: CatalogEntry[];
  connectedIds: ReadonlySet<string>;
  onEnable: (exchangeId: ExchangeId) => void;
}

function ExchangeList({ entries, connectedIds, onEnable }: ExchangeListProps): React.JSX.Element {
  if (entries.length === 0) {
    return (
      <div style={{ padding: 'var(--ts-space-4)', color: 'var(--ts-text-tertiary)', fontSize: 'var(--ts-font-sm)', textAlign: 'center' }}>
        No exchanges match your filter.
      </div>
    );
  }

  return (
    <ScrollArea>
      <div style={listStyle}>
        {entries.map((entry) => {
          const isConnected = connectedIds.has(entry.id);
          return (
            <div key={entry.id} style={entryStyle}>
              <div style={entryInfoStyle}>
                <span style={entryNameStyle}>{entry.name}</span>
                <span style={entryDescStyle}>{entry.description}</span>
              </div>
              {isConnected ? (
                <Badge variant="success">Connected</Badge>
              ) : (
                <Button
                  variant="primary"
                  size="sm"
                  onClick={() => onEnable(entry.id)}
                >
                  Enable
                </Button>
              )}
            </div>
          );
        })}
      </div>
    </ScrollArea>
  );
}

AddExchangeBrowser.displayName = 'AddExchangeBrowser';
